  { id:"mv-halfling-trickster",name:"Halfling Trickster",source:"mv",level:3,role:"Lurker",xp:150,size:"Small",origin:"Natural",type:"Humanoid",hp:35,ac:17,fort:15,ref:17,will:17,initiative:9,perception:6,speed:"6",powers:[{name:"Nimble Reaction",action:"Trait",description:"The halfling gains a +2 bonus to AC against opportunity attacks"},{name:"Bamboozle",action:"Trait",description:"When the halfling ends a turn in which it did not attack and it has cover or concealment from a creature, it is hidden from that creature until the end of its next turn"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d6 + 4 damage, or 4d6 + 8 if the halfling was hidden from the target when it attacked."},{name:"Smoke Pellet",action:"Minor",description:"Effect: Area burst 1 within 10. Squares in the burst are lightly obscured until the end of the halfling's next turn. Skills Acrobatics +12, Athletics +8, Bluff +10, Thievery +12"}],alignment:"Unaligned",languages:["Common Equipment : smoke pellet x4","leather armor","short sword . Monster Vault","page(s) 169","Dungeon Magazine 193."] },
  { id:"mv-hobgoblin-battle-guard",name:"Hobgoblin Battle Guard",source:"mv",level:3,role:"Soldier",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:49,ac:19,fort:17,ref:15,will:15,initiative:5,perception:8,speed:"6",senses:["Low-light vision"],powers:[{name:"Flail",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d10 + 5 damage, and the hobgoblin marks the target until the start of the hobgoblin's next turn."},{name:"Phalanx Movement",action:"Move",description:"Effect: Close burst 1 (allies in the burst). The hobgoblin and each target can shift 1 square as a free action. The target must shift to a square adjacent to the hobgoblin."},{name:"Share Shield",action:"Triggered",description:"Trigger: An adjacent ally is hit by an attack against AC or Reflex. Effect (Immediate Interrupt): The ally gains a +2 bonus to AC and Reflex against the triggering attack."}],alignment:"Unaligned",languages:["Common","Goblin Equipment : chainmail","flail","heavy shield . Monster Vault","page(s) 157","Dungeon Magazine 220."] },
  { id:"mv-hobgoblin-beast-master",name:"Hobgoblin Beast Master",source:"mv",level:3,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:47,ac:17,fort:17,ref:15,will:15,initiative:3,perception:1,speed:"6",senses:["Low-light vision"],powers:[{name:"Beast Master's Exhortation",action:"Trait",description:"When an allied beast or magical beast that is adjacent to the hobgoblin hits with an attack, that beast gains 5 temporary hit points"},{name:"Goad",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d8 + 6 damage."},{name:"War Whip",action:"Standard",keywords:["weapon"],description:"Attack: Melee 3 (one creature); +8 vs. AC Hit: 2d4 + 5 damage, and the target falls prone. Effect: The hobgoblin can slide the target 1 square. Attack Command ✦ At-Will Effect: Melee 1 (one beast or magical beast ally). The target can make a basic attack as a free action."},{name:"Phalanx Movement",action:"Move",description:"Effect: Close burst 1 (allies in the burst). The hobgoblin and each target can shift 1 square as a free action. The target must shift to a square adjacent to the hobgoblin."}],alignment:"Unaligned",languages:["Common","Goblin Equipment : goad (war pick)","leather armor","whip . Monster Vault","page(s) 156","Dungeon Magazine 213."] },
  { id:"mv-hobgoblin-spear-soldier",name:"Hobgoblin Spear Soldier",source:"mv",level:3,role:"Skirmisher",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:48,ac:17,fort:17,ref:15,will:15,initiative:5,perception:3,speed:"6",senses:["Low-light vision"],powers:[{name:"Threatening Reach",action:"Trait",description:"The hobgoblin can make opportunity attacks against enemies within its weapon's reach (2 squares)"},{name:"Longspear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +8 vs. AC Hit: 1d10 + 6 damage."},{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +8 vs. AC Hit: 2d6 + 4 damage."},{name:"Phalanx Movement",action:"Move",description:"Effect: The hobgoblin and each ally adjacent to it can shift 1 square as a free action. The allies must end adjacent to the hobgoblin."},{name:"Tactical Withdrawal",action:"Triggered",description:"Trigger: An enemy enters a square adjacent to the hobgoblin. Effect (Immediate Reaction): The hobgoblin shifts up to 3 squares."}],alignment:"Unaligned",languages:["Common","Goblin Equipment : chainmail","javelin x6","longspear . Monster Vault","page(s) 157","Dungeon Magazine 208","Dungeon Magazine 220."] },
  { id:"mv-poisonscale-brawler",name:"Poisonscale Brawler",source:"mv",level:3,role:"Brute",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:55,ac:15,fort:15,ref:13,will:12,initiative:3,perception:1,speed:"6 (swamp walk)",powers:[{name:"Club",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 2d6 + 7 damage."},{name:"Crushing Grasp",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the brawler); +6 vs. Fortitude Hit: 3d6 + 7 damage. Miss: Half damage."},{name:"Feral Grab",action:"Minor",description:"1/round Requirement: The brawler must not be grabbing a creature Attack: Melee 1 (one creature that isn't grabbed); +6 vs. Reflex Hit: The brawler grabs the target (escape DC 13). Skills Athletics +10, Stealth +8"}],alignment:"Unaligned",languages:["Draconic Equipment : club . Monster Vault","page(s) 187."] },
  { id:"mv-poisonscale-needler",name:"Poisonscale Needler",source:"mv",level:3,role:"Artillery",roleModifier:"Minion",xp:38,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:17,fort:13,ref:16,will:14,initiative:5,perception:3,speed:"6 (swamp walk)",powers:[{name:"Sniper",action:"Trait",description:"A hidden needler that misses with a ranged attack remains hidden"},{name:"Claw",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 5 damage."},{name:"Blowgun",action:"Standard",keywords:["poison","weapon"],description:"Attack: Ranged 10 (one creature); +10 vs. AC Hit: 5 poison damage. On a critical hit, the target also falls unconscious (save ends)."}],alignment:"Unaligned",languages:["Draconic Equipment : poisoned blowgun needle x10","blowgun . Monster Vault","page(s) 187."] },
  { id:"mv-scurrying-wererat",name:"Scurrying Wererat",source:"mv",level:3,role:"Skirmisher",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:37,ac:17,fort:16,ref:14,will:13,initiative:7,perception:7,speed:"6, climb 4 (rat or hybrid form only)",senses:["Low-light vision"],powers:[{name:"Regeneration",action:"Trait",description:"The wererat regains 5 hit points whenever it starts its turn and has at least 1 hit point"},{name:"When",action:"Trait",description:"the wererat takes damage from a silvered weapon, its regeneration does not function on its next turn"},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Requirement: The wererat must be in human or hybrid form Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d6 + 6 damage, or 2d6 + 6 if the wererat has combat advantage against the target."},{name:"Bite",action:"Standard",keywords:["disease"],description:"Requirement: The wererat must be in rat or hybrid form Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d4 + 4 damage. If the target is granting combat advantage to the wererat, it also takes ongoing 5 damage (save ends). At the end of the encounter, the target makes a saving throw. On a failure, the target contracts wererat filth fever (stage 1)."},{name:"Rat Scurry",action:"Move",description:"Requirement: The wererat must be in rat form. Effect: The wererat shifts up to its speed."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The wererat alters its physical form to appear as a Tiny rat, or a Medium unique human or hybrid. Skills Bluff +6, Stealth +10"}],alignment:"Unaligned",languages:["Common Equipment : dagger . Wererat Filth Fever Level 3 Disease Stage 0 : The target recovers from the disease. Stage 1 : While affected by stage 1","the target loses a healing surge. Stage 2 : While affected by stage 2","the target loses a healing surge. The target also takes a -2 penalty to AC","Fortitude","and Reflex. Stage 3 : While affected by stage 3","the target loses all healing surges and cannot regain hit points. The target also takes a -2 penalty to AC","Fortitude","and Reflex. Check : At the end of each extended rest","the target makes an Endurance check if it is at stage 1 or 2. 8 or lower : The stage of the disease increases by one. 9-12 : No Change 13 or higher : The stage of the disease decreases by one. Monster Vault","page(s) 194","Dungeon Magazine 193","Dungeon Magazine 217."] },
  { id:"mv-spider-swarm",name:"Spider Swarm",source:"mv",level:3,role:"Soldier",xp:150,size:"Medium",origin:"Natural",type:"Beast",keywords:["spider","swarm"],hp:44,ac:19,fort:13,ref:16,will:15,initiative:6,perception:3,speed:"6, climb 6 (spider climb)",senses:["Tremorsense 5"],resist:["half damage from melee and ranged attacks"],vulnerable:["5 to close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",description:"Aura 1 Any enemy that starts its turn in the aura is slowed until the start of its next turn"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for at least one of the creatures it comprises"},{name:"Web Walk",action:"Trait",description:"The spider ignores difficult terrain composed of webs"},{name:"Swarm of Fangs",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +6 vs. Reflex Hit: 1d6 + 3 damage, and ongoing 5 poison damage (save ends). Skills Athletics +6, Stealth +9"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 301","Dungeon Magazine 210","Dungeon Magazine 211","Dungeon Magazine 218","Dungeon Magazine 220."] },
  { id:"mv-town-guard",name:"Town Guard",source:"mv",level:3,role:"Soldier",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:47,ac:19,fort:16,ref:15,will:14,initiative:5,perception:6,speed:"5",powers:[{name:"Halberd",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +8 vs. AC Hit: 1d10 + 5 damage, and the town guard marks the target until the end of the town guard's next turn."},{name:"Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +8 vs. AC Hit: 1d8 + 5 damage."},{name:"Powerful Strike",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 2 (one creature); +8 vs. AC Hit: 2d10 + 5 damage, and the target falls prone."},{name:"Interceding Strike",action:"Triggered",keywords:["weapon"],description:"Trigger: An enemy marked by the town guard makes an attack that doesn't include it as a target. Attack (Immediate Interrupt): Melee 2 (the triggering enemy); +8 vs. AC Hit: 1d10 + 5 damage. Skills Streetwise +7"}],alignment:"Unaligned",languages:["Common Equipment : chainmail","crossbow","crossbow bolt x20","halberd . Monster Vault","page(s) 171","Dungeon Magazine 195","Dungeon Magazine 197","Dungeon Magazine 204","Dungeon Magazine 207."] },
  { id:"mv-bugbear-thug",name:"Bugbear Thug",source:"mv",level:4,role:"Brute",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",hp:65,ac:16,fort:15,ref:15,will:11,initiative:7,perception:8,speed:"6",senses:["Low-light vision"],powers:[{name:"Bushwhack",action:"Trait",description:"The bugbear gains a +4 bonus to attack rolls against a creature that has no allies adjacent to it"},{name:"Morningstar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d8 + 6 damage, or 3d8 + 6 if the bugbear has combat advantage against the target."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +9 vs. AC Hit: 1d6 + 6 damage. Skills Stealth +12"}],alignment:"Unaligned",languages:["Common","Goblin Equipment : handaxe x2","leather armor","morningstar . Monster Vault","page(s) 159","Dungeon Magazine 208","Dungeon Magazine 213","Dungeon Magazine 220."] },
  { id:"mv-duergar-thug",name:"Duergar Thug",source:"mv",level:4,role:"Brute",roleModifier:"Minion",xp:44,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:16,fort:17,ref:15,will:14,initiative:4,perception:4,speed:"5",senses:["Darkvision"],resist:["5 fire,","5 poison"],powers:[{name:"Warhammer",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 8 damage."},{name:"Infernal Quills",action:"Minor",keywords:["poison"],recharge:"Encounter",description:"Attack: Ranged 3 (one creature); +9 vs. AC Hit: 6 damage, and ongoing 2 poison damage (save ends)."}],alignment:"Unaligned",languages:["Common","Deep Speech","Dwarven Equipment : chainmail","warhammer . Monster Vault","page(s) 96","Dungeon Magazine 193."] },
  { id:"mv-flesh-crazed-zombie",name:"Flesh-Crazed Zombie",source:"mv",level:4,role:"Skirmisher",xp:175,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:55,ac:18,fort:17,ref:16,will:14,initiative:6,perception:3,speed:"6 (8 when charging)",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Flesh-Crazed Charge",action:"Trait",description:"While the zombie is charging, its movement does not provoke opportunity attacks"},{name:"Zombie Weakness",action:"Trait",description:"A critical hit automatically reduces the zombie to 0 hit points"},{name:"Club",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d8 + 6 damage, or 2d8 + 6 if the zombie charged the target."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d6 + 5 damage, and the target is dazed until the end of the zombie's next turn."},{name:"Deathless Hunger",action:"Triggered",recharge:"Encounter",description:"Trigger: The zombie is reduced to 0 hit points, but not by a critical hit. Effect (No Action): Roll a d20. On a 15 or higher, the zombie is instead reduced to 1 hit point."}],alignment:"Unaligned",languages:["- Equipment : club . Monster Vault","page(s) 295","Dungeon Magazine 187","Dungeon Magazine 192."] },
  { id:"mv-greenscale-raider-skirmisher",name:"Greenscale Raider (Skirmisher)",source:"mv",level:4,role:"Skirmisher",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",hp:54,ac:18,fort:17,ref:16,will:15,initiative:6,perception:8,speed:"6 (swamp walk)",powers:[{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d8 + 6 damage."},{name:"Sidestep Attack",action:"Standard",keywords:["weapon"],description:"Effect: The hunter can shift 1 square and then use spear."},{name:"Feral Tail Lash",action:"Minor",description:"Requirement: The hunter must be bloodied. Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d6 damage, and the hunter can shift 1 square. Skills Athletics +10, Stealth +9"}],alignment:"Unaligned",languages:["Draconic Equipment : light shield","spear . Monster Vault","page(s) 189."] },
  { id:"mv-hobgoblin-warmonger",name:"Hobgoblin Warmonger",source:"mv",level:4,role:"Artillery",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:46,ac:18,fort:15,ref:17,will:16,initiative:6,perception:4,speed:"6",senses:["Low-light vision"],powers:[{name:"Mace",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d8 + 6 damage."},{name:"Longbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 30 (one creature); +11 vs. AC Hit: 1d10 + 7 damage, and the target grants combat advantage until the start of the hobgoblin's next turn."},{name:"Battle Cry",action:"Standard",keywords:["charm"],recharge:"Recharge when first bloodied",description:"Attack: Area burst 1 within 10 (enemies in the burst); +9 vs. Will Hit: The target makes a basic attack as a free action against a creature of the hobgoblin's choice. Effect: Each ally in the burst can charge or make a basic attack as a free action. If an ally hits with the attack granted by this power, that ally gains 5 temporary hit points."},{name:"Phalanx Movement",action:"Move",description:"Effect: The hobgoblin and each ally adjacent to it can shift 1 square as a free action. The allies must end adjacent to the hobgoblin."}],alignment:"Unaligned",languages:["Common","Goblin Equipment : arrow x20","chainmail","longbow","mace . Monster Vault","page(s) 158","Dungeon Magazine 208","Dungeon Magazine 220."] },
  { id:"mv-hulking-zombie",name:"Hulking Zombie",source:"mv",level:4,role:"Brute",xp:175,size:"Large",origin:"Natural",type:"Animate",keywords:["undead"],hp:70,ac:16,fort:18,ref:14,will:14,initiative:1,perception:1,speed:"4",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Zombie Weakness",action:"Trait",description:"A critical hit automatically reduces the zombie to 0 hit points"},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +9 vs. AC Hit: 2d12 + 2 damage, or 2d12 + 7 against a prone target or one that is grabbed by another creature."},{name:"Zombie Rush",action:"Standard",description:"Effect: The zombie charges and makes the following attack in place of a melee basic attack Attack: Melee 2 (one creature); +7 vs. Fortitude Hit: 2d12 + 2 damage, and the zombie pushes the target 1 square and knocks it prone."},{name:"Deathless Hunger",action:"Triggered",recharge:"Encounter",description:"Trigger: The zombie is reduced to 0 hit points, but not by a critical hit. Effect (No Action): Roll a d20. On a 15 or higher, the zombie is instead reduced to 1 hit point."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 294","Dungeon Magazine 211."] },
  { id:"mv-bear",name:"Bear",source:"mv",level:5,role:"Brute",xp:200,size:"Large",origin:"Natural",type:"Beast",hp:80,ac:17,fort:19,ref:16,will:16,initiative:3,perception:3,speed:"8",powers:[{name:"Devour",action:"Trait",description:"Any creature grabbed by the bear at the start of the bear's turn takes 1d8 + 5 damage"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d8 + 7 damage."},{name:"Bear Grab",action:"Standard",recharge:"Recharge when first bloodied",description:"Effect: The bear uses claw twice against the same target. If either attack hits, the target falls prone, and the bear grabs the target (escape DC 15) if it has fewer than two creatures grabbed."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 296","Dungeon Magazine 205","Dungeon Magazine 220."] },
  { id:"mv-bugbear-backstabber",name:"Bugbear Backstabber",source:"mv",level:5,role:"Skirmisher",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:63,ac:19,fort:18,ref:18,will:15,initiative:9,perception:8,speed:"6",senses:["Low-light vision"],powers:[{name:"Bushwhack",action:"Trait",description:"The bugbear gains a +4 bonus to attack rolls against a creature that has no allies adjacent to it"},{name:"Expert Ambusher",action:"Trait",description:"If the bugbear is hidden from its target when it makes an attack, the attack deals 5 extra damage"},{name:"Greatsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d10 + 6 damage."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +10 vs. AC Hit: 2d6 + 5 damage."},{name:"Stealthy Positioning",action:"Move",description:"Effect: The bugbear shifts up to its speed. If it has any cover at the end of the move, it can make a Stealth check to become hidden, with no penalty for movement. Skills Stealth +12"}],alignment:"Unaligned",languages:["Common","Goblin Equipment : greatsword","handaxe x4","leather armor . Monster Vault","page(s) 159","Dungeon Magazine 212."] },
  { id:"mv-carrion-crawler-scuttler",name:"Carrion Crawler Scuttler",source:"mv",level:5,role:"Skirmisher",xp:200,size:"Large",origin:"Aberrant",type:"Beast",hp:63,ac:19,fort:18,ref:16,will:17,initiative:5,perception:3,speed:"8, climb 8 (spider climb)",senses:["Darkvision"],powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d8 + 4 damage, or 3d8 + 4 against a dazed target."},{name:"Tentacles",action:"Standard",description:"Attack: Melee 2 (one creature); +8 vs. Fortitude, or +10 Fortitude against a prone target Hit: The target is dazed (save ends). The carrion crawler shifts up to its speed, pulling the target with it."},{name:"Unsettling Scuttle",action:"Move",description:"Effect: The carrion crawler shifts up to its speed. It can move through enemy spaces and climb during the shift. Each time the carrion crawler enters an enemy space for the first time during this movement, it makes the following attack against that enemy. Attack: Melee 0 (creature in space); +8 vs. Reflex Hit: The target falls prone."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 32","Dungeon Magazine 195."] },
  { id:"mv-dryad-recluse",name:"Dryad Recluse",source:"mv",level:5,role:"Lurker",xp:200,size:"Large",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:50,ac:19,fort:16,ref:18,will:17,initiative:10,perception:10,speed:"8 (forest walk)",powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 6 damage."},{name:"Sylvan Charm",action:"Standard",keywords:["charm"],description:"Attack: Ranged 5 (one creature); +8 vs. Will Hit: The dryad pulls the target up to 5 squares to a square adjacent to it. The target is charmed until it is no longer adjacent to the dryad or until the dryad uses this power again. A charmed creature is immobilized and can't attack the dryad. When an enemy's melee or ranged attack hits the dryad, it deals half damage to the dryad and half damage to the charmed creature. If the attacker is adjacent to the charmed creature, the charmed creature must make a melee basic attack (of the dryad's choice) against the enemy as a free action."},{name:"Treestride",action:"Move",keywords:["teleportation"],description:"Requirement: The dryad must be adjacent to a tree or a Large plant. Effect: The dryad teleports up to 8 squares to a square adjacent to a tree or a Large plant. Any creature charmed by the dryad teleports with the dryad to a square adjacent to it."},{name:"Deceptive Veil",action:"Minor",keywords:["illusion"],description:"Effect: The dryad disguises itself to appear as a Medium humanoid (usually a beautiful elf or eladrin) until it uses deceptive veil again or until it drops to 0 hit points. Other creatures can make a DC 27 Insight check to discern that the form is an illusion."}],alignment:"Unaligned",languages:["Elven Monster Vault","page(s) 91","Dungeon Magazine 210","Dungeon Magazine 220."] },
  { id:"mv-duergar-raid-leader",name:"Duergar Raid Leader",source:"mv",level:5,role:"Artillery",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:51,ac:19,fort:17,ref:19,will:15,initiative:3,perception:4,speed:"5",senses:["Darkvision"],resist:["5 fire,","5 poison"],powers:[{name:"Warhammer",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d10 + 5 damage."},{name:"Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +12 vs. AC Hit: 1d8 + 8 damage. Raid Leader's Command ✦ At-Will Effect: Ranged 5 (one ally). The target can make a basic attack as a free action."},{name:"Infernal Quills",action:"Minor",keywords:["poison"],recharge:"Encounter",description:"Attack: Ranged 3 (one creature); +12 vs. AC Hit: 1d8 + 4 damage, and the target takes a -2 penalty to attack rolls and ongoing 5 poison damage (save ends both). Skills Dungeoneering +9"}],alignment:"Unaligned",languages:["Common","Deep Speech","Dwarven Equipment : chainmail","crossbow","warhammer . Monster Vault","page(s) 96","Dungeon Magazine 197."] },
  { id:"mv-gargoyle-rake",name:"Gargoyle Rake",source:"mv",level:5,role:"Lurker",xp:200,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["earth"],hp:52,ac:19,fort:17,ref:15,will:15,initiative:8,perception:9,speed:"6, fly 8",senses:["Darkvision"],resist:["20 to all damage, gains","5 temporary hit points at the start of each of its turns, and cannot take actions except to end the effect. When the gargoyle ends the effect, it gains a +15 bonus to its next damage roll before the end of its next turn. Skills Stealth +9"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d10 + 4 damage plus 2 extra damage for each one of the gargoyle's allies adjacent to the target."},{name:"Swoop Attack",action:"Standard",description:"Effect: The gargoyle flies up to its fly speed and uses claw at the end of the move. This movement does not provoke opportunity attacks. Stone Form ✦ At-Will Effect: The gargoyle enters stone form until it ends the effect as a minor action. While in this form, it gains tremorsense 10 and resist 20 to all damage, gains 5 temporary hit points at the start of each of its turns, and cannot take actions except to end the effect. When the gargoyle ends the effect, it gains a +15 bonus to its next damage roll before the end of its next turn. Skills Stealth +9"}],alignment:"Unaligned",languages:["Primordial Monster Vault","page(s) 122","Madness at Gardmore Abbey","page(s) 4-2."] },
  { id:"mv-gnome-spy",name:"Gnome Spy",source:"mv",level:5,role:"Lurker",xp:200,size:"Small",origin:"Fey",type:"Humanoid",hp:51,ac:19,fort:16,ref:18,will:17,initiative:10,perception:8,speed:"5",senses:["Low-light vision"],powers:[{name:"Reactive Stealth",action:"Trait",description:"If the gnome has cover or concealment when it rolls initiative, it can make a Stealth check to become hidden"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 4 damage, or 4d6 + 4 if the gnome was invisible to the target when it attacked."},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +10 vs. AC Hit: 2d4 + 5 damage, or 4d4 + 5 if the gnome was invisible to the target when it attacked. Vanish from Sight (illusion) ✦ At-Will Effect: The gnome becomes invisible until it hits or misses with an attack or until the end of its next turn."},{name:"Fade Away",action:"Triggered",keywords:["illusion"],recharge:"Encounter",description:"Trigger: The gnome takes damage. Effect (Immediate Reaction): The gnome becomes invisible until it hits or misses with an attack or until the end of its next turn. Skills Bluff +10, Stealth +11"}],alignment:"Unaligned",languages:["Common","Elven Equipment : dagger","leather armor","short sword . Monster Vault","page(s) 148","Dungeon Magazine 185."] },
  { id:"mv-ravenous-ghoul",name:"Ravenous Ghoul",source:"mv",level:5,role:"Brute",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:76,ac:17,fort:18,ref:17,will:15,initiative:4,perception:1,speed:"8, climb 4",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 3d8 + 4 damage."},{name:"Ravenous Bite",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 3d8 + 6 damage, and ongoing 5 damage (save ends). Skills Stealth +9"}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 128","Dungeon Magazine 187","Dungeon Magazine 218."] },
  { id:"mv-shark",name:"Shark",source:"mv",level:5,role:"Brute",xp:200,size:"Medium",origin:"Natural",type:"Beast",keywords:["aquatic"],hp:75,ac:17,fort:18,ref:17,will:17,initiative:4,perception:9,speed:"1 (clumsy), swim 8",senses:["Low-light vision"],powers:[{name:"Aquatic",action:"Trait",description:"The shark can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Blood Frenzy",action:"Trait",description:"The shark gains a +2 bonus to attack rolls and a +4 bonus to damage rolls against bloodied creatures"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d8 + 7 damage."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 299."] },
  { id:"mv-spitting-cobra",name:"Spitting Cobra",source:"mv",level:5,role:"Soldier",roleModifier:"Minion",xp:50,size:"Small",origin:"Natural",type:"Beast",keywords:["reptile"],hp:1,ac:21,fort:17,ref:18,will:17,initiative:8,perception:4,speed:"6, climb 6",senses:["Low-light vision"],powers:[{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 6 poison damage, and the cobra marks the target until the end of the cobra's next turn."},{name:"Blinding Spittle",action:"Standard",keywords:["poison"],recharge:"Recharge 3-6",description:"Attack: Ranged 5 (one creature); +8 vs. Reflex Hit: 6 poison damage, and the target is blinded (save ends)."}],alignment:"Unaligned",languages:["- Dungeon Magazine 182","Monster Vault","page(s) 300."] },
  { id:"mv-tiefling-fury",name:"Tiefling Fury",source:"mv",level:5,role:"Soldier",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:63,ac:21,fort:18,ref:17,will:18,initiative:4,perception:2,speed:"6",senses:["Low-light vision"],resist:["10 fire"],powers:[{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d8 + 8 damage. Effect: The tiefling marks the target until the end of the target's next turn."},{name:"Tail Trip",action:"Triggered",description:"Trigger: An enemy marked by the tiefling shifts. Attack (Immediate Interrupt): Melee 1 (the triggering enemy); +10 vs. Reflex Hit: The target falls prone, and the tiefling uses longsword against it. Defiant Curse ✦ At-Will Trigger: An enemy hits the tiefling. Effect (Free Action): Close burst 10 (the triggering enemy in the burst). The tiefling marks the target until the end of the target's next turn. Skills Bluff +10, Stealth +7"}],alignment:"Unaligned",languages:["Common Equipment : leather armor","longsword . Monster Vault","page(s) 262","Dungeon Magazine 192."] },
  { id:"mv-zombie-shambler",name:"Zombie Shambler",source:"mv",level:5,role:"Brute",roleModifier:"Minion",xp:50,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:1,ac:17,fort:18,ref:15,will:15,initiative:1,perception:1,speed:"4",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 8 damage."},{name:"Deathless Hunger",action:"Triggered",recharge:"Encounter",description:"Trigger: The zombie is reduced to 0 hit points, but not by a critical hit. Effect (No Action): Roll a d20. On a 15 or higher, the zombie is instead reduced to 1 hit point."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 295","Dungeon Magazine 192","Dungeon Magazine 207","Dungeon Magazine 218."] },
  { id:"mv-blackscale-crusher",name:"Blackscale Crusher",source:"mv",level:6,role:"Brute",xp:250,size:"Large",origin:"Natural",type:"Humanoid",hp:86,ac:18,fort:19,ref:16,will:16,initiative:6,perception:4,speed:"8 (swamp walk)",powers:[{name:"Greatclub",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +11 vs. AC Hit: 2d10 + 6 damage, and the bruiser can push the target 1 square."},{name:"Feral Bite",action:"Minor",description:"Requirement: The bruiser must be bloodied Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d6 + 4 damage."},{name:"Tail Swipe",action:"Triggered",recharge:"Recharge when first bloodied",description:"Trigger: The bruiser takes damage from an enemy. Attack (Immediate Reaction): Close blast 2 (creatures in the blast); +9 vs. Reflex Hit: 2d8 + 6 damage, and the target falls prone."}],alignment:"Unaligned",languages:["Draconic Equipment : greatclub . Monster Vault","page(s) 191."] },
  { id:"mv-death-husk-stirge",name:"Death Husk Stirge",source:"mv",level:6,role:"Skirmisher",xp:250,size:"Small",origin:"Natural",type:"Animate",keywords:["undead"],hp:71,ac:20,fort:16,ref:20,will:18,initiative:9,perception:6,speed:"2, fly 6",senses:["Darkvision"],resist:["10 necrotic"],immune:["poison"],powers:[{name:"Necromantic Flyer",action:"Trait",description:"A death husk stirge that takes radiant damage cannot fly until the end of its next turn; if in the air, it falls"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 7 damage, and the death husk stirge recharges rotted blood."},{name:"Rotted Blood",action:"Standard",keywords:["necrotic"],recharge:"Encounter",description:"Attack: Close blast 3 (living creatures in the blast); +9 vs. Fortitude Hit: 1d6 + 7 necrotic damage, and the target is blinded until the end of the stirge's next turn. Effect: Undead in the blast can shift 2 squares as a free action."},{name:"Nimble Wing",action:"Move",description:"Effect: The death husk stirge flies 4 squares. This movement does not provoke opportunity attacks."},{name:"Necrotic Miasma",action:"Triggered",keywords:["necrotic"],description:"Trigger: The death husk stirge drops to 0 hit points. Attack (No Action): Close burst 2 (living creatures in the burst); +9 vs. Fortitude Hit: 5 necrotic damage, and the target is weakened until the end of its next turn."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 260","Dungeon Magazine 206."] },
  { id:"mv-frenzied-werewolf",name:"Frenzied Werewolf",source:"mv",level:6,role:"Brute",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:78,ac:18,fort:19,ref:18,will:16,initiative:6,perception:9,speed:"6 (8 in wolf form)",senses:["Low-light vision"],powers:[{name:"Regeneration",action:"Trait",description:"The werewolf regains 5 hit points whenever it starts its turn and has at least 1 hit point"},{name:"When",action:"Trait",description:"the werewolf takes damage from a silvered weapon, its regeneration does not function on its next turn"},{name:"Claw",action:"Standard",description:"Requirement: The werewolf must be in wolf or hybrid form. Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 3 damage, or 2d8 + 8 against a bloodied target, and the target falls prone."},{name:"Bite",action:"Standard",keywords:["disease"],description:"Requirement: The werewolf must be in wolf or hybrid form. Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d10 + 7 damage. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts werewolf moon frenzy (stage 1)."},{name:"Club",action:"Standard",keywords:["weapon"],description:"Requirement: The werewolf must be in human or hybrid form. Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 4 damage, or 2d8 + 9 against a bloodied target."},{name:"Lycanthrope Fury",action:"Standard",description:"Requirement: The werewolf must be in hybrid form. Effect: The werewolf uses claw and bite. Then the werewolf takes 5 damage."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The werewolf alters its physical form to appear as a Medium wolf, unique human, or hybrid. Skills Bluff +8, Intimidate +8"}],alignment:"Unaligned",languages:["Common Equipment : club . Werewolf Moon Frenzy Level 6 Disease Stage 0 : The target recovers from the disease. Stage 1 : While affected by stage 1","the target takes a -2 penalty to Will. Stage 2 : While affected by stage 2","whenever the target becomes bloodied","it makes a melee basic attack as a free action against an ally adjacent to it. Stage 3 : While affected by stage 3","whenever the target is hit by an attack","it makes a melee basic attack as a free action against an ally adjacent to it. Check : At the end of each extended rest","the target makes an Endurance check if it is at stage 1 or 2. 10 or lower : The stage of the disease increases by one. 11-14 : No Change 15 or higher : The stage of the disease decreases by one. Monster Vault","page(s) 195","Dungeon Magazine 185","Dungeon Magazine 193","Dungeon Magazine 194","Dungeon Magazine 214."] },
  { id:"mv-gnoll-blood-caller",name:"Gnoll Blood Caller",source:"mv",level:6,role:"Soldier",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:70,ac:22,fort:19,ref:18,will:17,initiative:8,perception:5,speed:"8",senses:["Low-light vision"],powers:[{name:"Pack Attack",action:"Trait",description:"The gnoll's attacks deal 5 extra damage to any enemy that has two or more of the gnoll's allies adjacent to it"},{name:"Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 7 damage, or 2d6 + 9 while the gnoll is bloodied. Effect: The gnoll marks the target until the end of the gnoll's next turn."},{name:"Blood Call",action:"Standard",keywords:["charm","psychic"],description:"Effect: The gnoll shifts up to 3 squares Attack: Close burst 5 (each creature marked by the gnoll in the burst); +9 vs. Will Hit: 1d10 + 9 psychic damage, and the gnoll pulls the target up to 3 squares."},{name:"Blood Frenzy",action:"Minor",description:"1/round Requirement: The gnoll must be bloodied. Effect: Close burst 1 (enemies in the burst). Each target takes 5 damage and is marked by the gnoll until the end of the gnoll's next turn."}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : leather armor . Monster Vault","page(s) 144","Madness at Gardmore Abbey","page(s) 4-26","Dungeon Magazine 221."] },
  { id:"mv-gnome-illusionist",name:"Gnome Illusionist",source:"mv",level:6,role:"Artillery",xp:250,size:"Medium",origin:"Fey",type:"Humanoid",hp:57,ac:20,fort:15,ref:17,will:18,initiative:5,perception:4,speed:"5",senses:["Low-light vision"],powers:[{name:"Gnarled Staff",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d8 + 6 damage."},{name:"Bedazzle",action:"Standard",keywords:["illusion","implement","radiant"],description:"Attack: Area burst 1 within 10 (enemies in the burst); +11 vs. Will Hit: 2d6 + 5 radiant damage, and the target grants combat advantage (save ends)."},{name:"See Me Not",action:"Standard",keywords:["illusion","implement","psychic"],recharge:"Recharge 4-6",description:"Attack: Close blast 3 (enemies in the blast); +9 vs. Will Hit: 2d6 + 10 psychic damage, and the target cannot see the gnome (save ends)."},{name:"There, Not There",action:"Move",keywords:["illusion","teleportation"],recharge:"Encounter",description:"Effect: The gnome teleports up to 5 squares and creates two duplicates of itself within 5 squares of its destination space. The duplicates last until the gnome attacks or until they are destroyed. Each duplicate has 1 hit point and the same ability scores and defenses as the gnome. The gnome can use its actions to have a duplicate act in any way it could, except that the duplicates cannot use powers and cannot flank."},{name:"Veil",action:"Minor",keywords:["illusion"],description:"Effect: The gnome can disguise itself and up to three allies within 5 squares of it to appear as any Small or Medium creatures. A creature can see through the disguise with a successful Insight check opposed by the gnome's Bluff check. Skills Bluff +13, Stealth +10"}],alignment:"Unaligned",languages:["Common","Elven Equipment : gnarled staff (quarterstaff)","robes. Monster Vault","page(s) 149","Dungeon Magazine 185","Dungeon Magazine 192","Dungeon Magazine 217."] },
  { id:"mv-greenscale-bog-mystic",name:"Greenscale Bog Mystic",source:"mv",level:6,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:70,ac:20,fort:17,ref:16,will:19,initiative:4,perception:7,speed:"6 (swamp walk)",powers:[{name:"Swamp Tangle",action:"Aura",description:"Aura 5 Whenever an enemy in the aura is hit by an attack, squares in the aura are difficult terrain for that enemy until the end of its next turn."},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 5 damage."},{name:"Bog Cloud",action:"Standard",keywords:["poison"],recharge:"Recharge 4-6",description:"Attack: Area burst 2 within 5 (creatures in the burst); +9 vs. Fortitude Hit: 2d6 + 7 poison damage, and the target is dazed until the end of the mystic's next turn. Miss: The target grants combat advantage until the end of the mystic's next turn."},{name:"Swamp's Grasp",action:"Standard",keywords:["zone"],recharge:"Encounter",description:"Attack: Area burst 2 within 5 (enemies in the burst); +9 vs. Reflex Hit: 2d6 + 4 damage, and the target is immobilized (save ends). Miss: Half damage, and the target is slowed (save ends). Effect: The burst creates a zone of difficult terrain until the end of the encounter. The zone does not affect creatures that have swamp walk"},{name:"Feral Tail Lash",action:"Minor",description:"Requirement: The mystic must be bloodied. Attack: Melee 1 (one creature); +9 vs. Reflex Hit: 1d6 damage, and the target is slowed until the end of the mystic's next turn. Skills Athletics +10, Nature +12, Stealth +9"}],alignment:"Unaligned",languages:["Draconic Equipment : spear . Monster Vault","page(s) 190","Dungeon Magazine 208."] },
  { id:"mv-ogre",name:"Ogre",source:"mv",level:6,role:"Brute",xp:250,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:90,ac:18,fort:20,ref:17,will:16,initiative:5,perception:3,speed:"8",powers:[{name:"Greatclub",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +11 vs. AC Hit: 2d10 + 6 damage."},{name:"Rock",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +11 vs. AC Hit: 2d6 + 5 damage."},{name:"Grand Slam",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Melee 2 (one creature); +11 vs. AC Hit: 4d10 + 4 damage, and the ogre pushes the target up to 2 squares and knocks it prone. Miss: Half damage, and the target falls prone."}],alignment:"Unaligned",languages:["Giant Equipment : rock x4","greatclub . Monster Vault","page(s) 216","Madness at Gardmore Abbey","page(s) 3-2","Dungeon Magazine 196","Dungeon Magazine 215","Dungeon Magazine 221."] },
  { id:"mv-orc-pummeler",name:"Orc Pummeler",source:"mv",level:6,role:"Controller",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:76,ac:20,fort:20,ref:17,will:16,initiative:5,perception:3,speed:"6",senses:["Low-light vision"],powers:[{name:"Stone Maul",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 7 damage, and the target falls prone."},{name:"Earthshaking Slam",action:"Standard",recharge:"Encounter",description:"Attack: Close burst 2 (creatures in the burst); +9 vs. Fortitude Hit: 3d6 + 5 damage, and the target is dazed until the end of the orc's next turn. Effect: The orc pushes each target up to 2 squares."},{name:"Intercepting Swat",action:"Triggered",recharge:"Recharge 3-6",description:"Trigger: An enemy makes an opportunity attack against the orc. Effect (Free Action): The orc uses stone maul against the triggering enemy. Savage Demise ✦ Encounter Trigger: The orc drops to 0 hit points. Effect (Free Action): The orc takes a standard action."}],alignment:"Unaligned",languages:["Common","Giant Equipment : stone maul","scale armor . Monster Vault","page(s) 228","Madness at Gardmore Abbey","page(s) 1-12","Dungeon Magazine 210","Dungeon Magazine 221."] },
  { id:"mv-orc-storm-shaman",name:"Orc Storm Shaman",source:"mv",level:6,role:"Artillery",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:54,ac:20,fort:16,ref:19,will:18,initiative:7,perception:6,speed:"6",senses:["Low-light vision"],powers:[{name:"Scimitar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d8 + 8 damage."},{name:"Lightning Strike",action:"Standard",keywords:["lightning"],description:"Attack: Ranged 30 (one creature); +11 vs. Reflex Hit: 1d10 + 8 lightning damage, and one enemy within 5 squares of the target takes 5 lightning damage."},{name:"Vengeful Whirlwind",action:"Standard",keywords:["lightning","thunder","zone"],recharge:"Recharge when first bloodied",description:"Attack: Area burst 1 within 10 (enemies in the burst); +11 vs. Fortitude Hit: 2d10 + 4 lightning and thunder damage, and the target falls prone. Then the shaman slides the target up to 2 squares. Miss: Half damage, and the shaman can slide the target 1 square. Effect: The burst creates a zone that lasts until the end of the orc's next turn. Any enemy that ends its turn in the zone takes 10 thunder and lightning damage."},{name:"Wind Walk",action:"Triggered",recharge:"Encounter",description:"Trigger: The shaman is first bloodied. Effect (Free Action): Until the end of the encounter, the shaman gains a fly speed of 8 but must land or fall at the end of each move."},{name:"Savage Demise",action:"Triggered",recharge:"Encounter",description:"Trigger: The orc drops to 0 hit points. Effect (Free Action): The orc takes a standard action."}],alignment:"Unaligned",languages:["Common","Giant Equipment : hide armor","scimitar . Monster Vault","page(s) 229","Dungeon Magazine 183","Madness at Gardmore Abbey","page(s) 3-12","Dungeon Magazine 210","Dungeon Magazine 221."] },
  { id:"mv-troglodyte-grunt",name:"Troglodyte Grunt",source:"mv",level:6,role:"Skirmisher",roleModifier:"Minion",xp:63,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:1,ac:20,fort:20,ref:18,will:16,initiative:6,perception:5,speed:"5",senses:["Darkvision"],powers:[{name:"Troglodyte Stench",action:"Aura",description:"Aura 1 Living enemies take a -2 penalty to attack rolls while in the aura."},{name:"Club",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 7 damage. Effect: The troglodyte shifts up to 2 squares."},{name:"Scatter",action:"Triggered",description:"Trigger: The troglodyte is targeted by a close or an area attack. Effect (Immediate Interrupt): The troglodyte shifts up to 2 squares to a square outside the triggering attack's area of effect."}],alignment:"Unaligned",languages:["Draconic Equipment : club . Monster Vault","page(s) 270","Dungeon Magazine 190","Dungeon Magazine 206","Dungeon Magazine 221."] },
  { id:"mv-wraith-figment",name:"Wraith Figment",source:"mv",level:6,role:"Skirmisher",roleModifier:"Minion",xp:63,size:"Medium",origin:"Shadow",type:"Humanoid",keywords:["undead"],hp:1,ac:18,fort:16,ref:20,will:17,initiative:8,perception:3,speed:"fly 6 (hover); phasing",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],powers:[{name:"Shadow Caress",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +9 vs. Reflex Hit: 7 necrotic damage, and the target is slowed until the end of the wraith's next turn."},{name:"Shadow Glide",action:"Move",recharge:"Encounter",description:"Effect: The wraith figment shifts up to 6 squares. Skills Stealth +11"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 287","Madness at Gardmore Abbey","page(s) 4-9","Dungeon Magazine 192","Dungeon Magazine 196","Dungeon Magazine 214","Dungeon Magazine 218."] },
  { id:"mv-demon-eye-gnoll",name:"Demon-Eye Gnoll",source:"mv",level:7,role:"Lurker",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:62,ac:21,fort:20,ref:20,will:18,initiative:11,perception:10,speed:"8",senses:["Low-light vision"],powers:[{name:"Abyssal Mind",action:"Aura",keywords:["charm","psychic","psychic"],description:"Aura 3 While the gnoll is bloodied, any enemy that ends its turn in the aura and can see the gnoll takes 5 psychic damage"},{name:"If",action:"Trait",description:"the enemy is dazed, it must also make a basic attack against its nearest ally as a free action"},{name:"Pack Attack",action:"Trait",description:"The gnoll's attacks deal 5 extra damage to any enemy that has two or more of the gnoll's allies adjacent to it"},{name:"Glaive",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 4d4 + 5 damage, or 6d4 + 15 if the target cannot see the gnoll."},{name:"Stare into the Abyss",action:"Standard",description:"Attack: Close burst 3 (enemies in the burst that can see the gnoll); +10 vs. Will Hit: The target is dazed until the end of the gnoll's next turn. Effect: The gnoll becomes invisible to the targets until the end of its next turn."}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : glaive","leather armor . Monster Vault","page(s) 146","Madness at Gardmore Abbey","page(s) 4-26."] },
  { id:"mv-doomspinner-spider",name:"Doomspinner Spider",source:"mv",level:7,role:"Controller",xp:300,size:"Large",origin:"Natural",type:"Beast",keywords:["spider"],hp:82,ac:21,fort:20,ref:19,will:19,initiative:6,perception:11,speed:"6, climb 6 (spider climb)",senses:["Tremorsense 10"],resist:["5 poison"],powers:[{name:"Web Walk",action:"Trait",description:"The spider ignores difficult terrain composed of webs"},{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 1d8 + 6 damage, and ongoing 5 poison damage, or ongoing 10 poison if the target is immobilized, restrained, stunned, or unconscious (save ends)."},{name:"Web Casting",action:"Standard",description:"Attack: Area burst 1 within 5 (creatures in the burst); +10 vs. Reflex Hit: The target is restrained (save ends). Effect: Squares in the burst are difficult terrain until the end of the encounter."},{name:"Draw to Doom",action:"Minor",description:"Attack: Ranged 5 (one creature); +10 vs. Fortitude Hit: The spider pulls the target up to 4 squares. Skills Athletics +12, Stealth +11"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 302","Dungeon Magazine 193."] },
  { id:"mv-dryad-hunter",name:"Dryad Hunter",source:"mv",level:7,role:"Skirmisher",xp:300,size:"Large",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:82,ac:21,fort:20,ref:20,will:18,initiative:9,perception:10,speed:"8 (forest walk)",powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 6 damage, or 3d8 + 8 if no other enemy is adjacent to the dryad."},{name:"Luring Feint",action:"Standard",description:"Effect: The dryad uses claw. If the attack hits, the dryad shifts up to 4 squares, pulling the target with it. If the attack misses, the dryad shifts up to its speed."},{name:"Treestride",action:"Move",keywords:["teleportation"],description:"Requirement: The dryad must be adjacent to a tree or a Large plant. Effect: The dryad teleports up to 8 squares to a square adjacent to a tree or a Large plant."},{name:"Deceptive Veil",action:"Minor",keywords:["illusion"],description:"Effect: The dryad disguises itself to appear as a Medium humanoid (usually a beautiful elf or eladrin) until it uses deceptive veil again or until it drops to 0 hit points. Other creatures can make a DC 28 Insight check to discern that the form is an illusion."}],alignment:"Unaligned",languages:["Elven Monster Vault","page(s) 92","Madness at Gardmore Abbey","page(s) 2-19","Dungeon Magazine 220."] },
  { id:"mv-eladrin-bow-mage",name:"Eladrin Bow Mage",source:"mv",level:7,role:"Artillery",roleModifier:"Minion",xp:75,size:"Medium",origin:"Fey",type:"Humanoid",hp:1,ac:21,fort:18,ref:21,will:19,initiative:7,perception:10,speed:"6",senses:["Low-light vision"],powers:[{name:"Force Arrow",action:"Standard",keywords:["force","weapon"],description:"Attack: Ranged 20 (one creature); +14 vs. AC Hit: 7 force damage, and the eladrin can push the target 1 square."}],alignment:"Unaligned",languages:["Common","Elven Monster Vault","page(s) 114","Dungeon Magazine 185","Dungeon Magazine 213."] },
  { id:"mv-gnome-assassin",name:"Gnome Assassin",source:"mv",level:7,role:"Skirmisher",xp:300,size:"Small",origin:"Fey",type:"Humanoid",hp:78,ac:21,fort:18,ref:20,will:19,initiative:9,perception:9,speed:"5",senses:["Low-light vision"],vulnerable:["5 radiant. In addition, it can make Stealth checks to become hidden if it has any cover or concealment. Sustain Minor: The shadowy form persists until the end of the gnome's next turn. Skills Stealth +12"],powers:[{name:"Katar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d6 + 8 damage, or 4d6 + 8 if the attack ended the gnome's shade form."},{name:"Shadow Step",action:"Move",keywords:["teleportation"],description:"Requirement: The gnome must be adjacent to a creature. Effect: The gnome teleports up to 3 squares to a square adjacent to a different creature, and any mark on the gnome ends."},{name:"Shade Form",action:"Minor",recharge:"Recharge when first bloodied",description:"Effect: The gnome assumes a shadowy form that lasts until it makes an attack roll or until the end of its next turn. While in this form, it is insubstantial and has vulnerable 5 radiant. In addition, it can make Stealth checks to become hidden if it has any cover or concealment. Sustain Minor: The shadowy form persists until the end of the gnome's next turn. Skills Stealth +12"}],alignment:"Unaligned",languages:["Common","Elven Equipment : katar x2","leather armor . Monster Vault","page(s) 150","Dungeon Magazine 192","Dungeon Magazine 200","Dungeon Magazine 214."] },
  { id:"mv-gray-company-soldier",name:"Gray Company Soldier",source:"mv",level:7,role:"Soldier",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:80,ac:23,fort:20,ref:18,will:19,initiative:7,perception:4,speed:"5",powers:[{name:"Grim Solidarity",action:"Trait",description:"If the soldier starts its turn adjacent to a creature that has grim solidarity, it can make a saving throw against one effect that a save can end"},{name:"Ancient Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 6 damage."},{name:"Strike of the Ancient Blade",action:"Triggered",keywords:["weapon"],description:"Trigger: An enemy adjacent to the soldier uses an attack power that doesn't include the soldier as a target. Attack (Immediate Reaction): Melee 1 (the triggering enemy); +10 vs. Fortitude Hit: 2d8 + 6 damage, and the soldier pushes the target 1 square and knocks it prone."},{name:"For the Glory of Nerath",action:"Triggered",keywords:["weapon"],recharge:"Encounter",description:"Trigger: An ally within 5 squares of the soldier drops to 0 hit points. Attack (Immediate Reaction): Close burst 1 (enemies in the burst); +12 vs. AC Hit: 2d8 + 9 damage, and ongoing 5 damage (save ends). Skills History +8"}],alignment:"Unaligned",languages:["Common Equipment : ancient longsword","heavy shield","plate armor . Monster Vault","page(s) 62."] },
  { id:"mv-human-thug",name:"Human Thug",source:"mv",level:7,role:"Skirmisher",roleModifier:"Minion",xp:75,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:21,fort:20,ref:17,will:18,initiative:5,perception:4,speed:"6",powers:[{name:"Rush",action:"Trait",description:"into Battle Whenever the thug hits a creature with a charge attack, the target grants combat advantage until the end of the thug's next turn"},{name:"Club",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 7 damage."}],alignment:"Unaligned",languages:["Common Equipment : club . Monster Vault","page(s) 172","Dungeon Magazine 183","Dungeon Magazine 187","Madness at Gardmore Abbey","page(s) 2-17","Dungeon Magazine 200","Dungeon Magazine 206."] },
  { id:"mv-human-transmuter",name:"Human Transmuter",source:"mv",level:7,role:"Controller",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:77,ac:21,fort:18,ref:19,will:20,initiative:3,perception:11,speed:"6",powers:[{name:"Staff",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d6 + 6 damage."},{name:"Capricious Earth",action:"Standard",keywords:["charm","implement"],description:"Attack: Area burst 2 within 5 (enemies in the burst); +10 vs. Will Hit: 2d10 + 6 damage, and the transmuter slides the target up to 3 squares. Miss: The transmuter can slide the target 1 square."},{name:"Beast Curse",action:"Standard",keywords:["implement","polymorph"],recharge:"Recharge 3-6",description:"Attack: Ranged 5 (one hexed enemy); +10 vs. Fortitude Hit: The transmuter alters the target's physical form to appear as a Tiny animal until the end of the transmuter's next turn. While in this form, the target cannot use powers or make attacks."},{name:"Hex Jump",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: Close burst 5 (one hexed creature in the burst). The transmuter and the target teleport, swapping positions."},{name:"Hex",action:"Minor",keywords:["charm","implement"],description:"1/round Attack: Close burst 5 (one enemy in the burst); +10 vs. Will Hit: The target is hexed until the end of the transmuter's next turn. While hexed, the target is slowed and takes a -2 penalty to attack rolls and damage rolls against the transmuter. Skills Arcana +10, Nature +11"}],alignment:"Unaligned",languages:["Common Equipment : robes","staff implement . Monster Vault","page(s) 172","Dungeon Magazine 183","Dungeon Magazine 193","Dungeon Magazine 206","Dungeon Magazine 218."] },
  { id:"mv-ogre-hunter",name:"Ogre Hunter",source:"mv",level:7,role:"Skirmisher",xp:300,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:84,ac:21,fort:20,ref:18,will:17,initiative:8,perception:5,speed:"8",powers:[{name:"Club",action:"Standard",keywords:["weapon"],description:"Attack: 2 (one creature); +12 vs. AC Hit: 2d8 + 6 damage."},{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +12 vs. AC Hit: 1d8 + 9 damage."},{name:"Hurling Charge",action:"Standard",recharge:"Recharge 3-6",description:"Effect: The ogre uses javelin. If its attack hits, the ogre charges as a free action."},{name:"Clear the Ground",action:"Move",description:"Attack: Close burst 2 (creatures in the burst); +10 vs. Fortitude Hit: The ogre pushes the target up to 2 squares. Effect: If the attack hits any of the targets, the ogre moves up to its speed."}],alignment:"Unaligned",languages:["Giant Equipment : club","javelin x6. Monster Vault","page(s) 218."] },
  { id:"mv-skeletal-legionary",name:"Skeletal Legionary",source:"mv",level:7,role:"Soldier",roleModifier:"Minion",xp:75,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:1,ac:23,fort:20,ref:20,will:18,initiative:9,perception:5,speed:"5",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],powers:[{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 7 damage. Effect: The legionary marks the target until the end of the legionary's next turn."},{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +12 vs. AC Hit: 7 damage. Effect: The legionary marks the target until the end of the legionary's next turn."}],alignment:"Unaligned",languages:["- Equipment : heavy shield","javelin x3","longsword","scale armor . Monster Vault","page(s) 257","Dungeon Magazine 187","Madness at Gardmore Abbey","page(s) 4-12","Dungeon Magazine 221."] },
  { id:"mv-young-bulette",name:"Young Bulette",source:"mv",level:7,role:"Lurker",xp:300,size:"Medium",origin:"Natural",type:"Beast",hp:68,ac:21,fort:20,ref:19,will:16,initiative:11,perception:6,speed:"6, burrow 6",senses:["Darkvision"],powers:[{name:"Ground Eruption",action:"Trait",description:"The squares of ground the bulette burrows into or emerges from become difficult terrain until the end of the encounter"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 1d10 + 4 damage. Submerge in Earth ✦ At-Will Requirement: The bulette must be aboveground. Effect: The bulette shifts 1 square and then burrows up to its burrow speed."},{name:"Snapping Jaws",action:"Standard",recharge:"Recharge when the bulette uses submerge in earth",description:"Requirement: The bulette must be underground. Effect: The bulette burrows up to its burrow speed to a square aboveground. This movement does not provoke opportunity attacks. When it first enters a square aboveground during this movement, it makes the following attack. Attack: Melee 1 (one creature); +12 vs. AC Hit: 4d10 + 8 damage."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 29."] },
  { id:"mv-dryad-witch",name:"Dryad Witch",source:"mv",level:8,role:"Controller",xp:350,size:"Large",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:84,ac:22,fort:18,ref:20,will:22,initiative:7,perception:14,speed:"8 (forest walk)",powers:[{name:"Thorny Vine",action:"Standard",description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d8 + 7 damage. Effect: The dryad can slide the target 1 square."},{name:"Beguiling Verdure",action:"Standard",keywords:["charm"],description:"Attack: Ranged 5 (one dazed creature); +11 vs. Will Hit: The dryad slides the target up to the target's speed, and the target must then make a basic attack as a free action against a creature of the dryad's choice."},{name:"Soporific Fragrance",action:"Standard",keywords:["charm"],recharge:"Recharge 3-6",description:"Attack: Close blast 3 (enemies in the blast); +11 vs. Will Hit: The target is dazed (save ends)."},{name:"Treestride",action:"Move",keywords:["teleportation"],description:"Requirement: The dryad must be adjacent to a tree or a Large plant Effect: The dryad teleports up to 8 squares to a square adjacent to a tree or a Large plant"},{name:"Deceptive Veil",action:"Minor",keywords:["illusion"],description:"Effect: The dryad disguises itself to appear as a Medium humanoid (usually a beautiful elf or eladrin) until it uses deceptive veil again or until it drops to 0 hit points. Other creatures can make a DC 29 Insight check to discern that the form is an illusion."}],alignment:"Unaligned",languages:["Elven Monster Vault","page(s) 93","Dungeon Magazine 185."] },
  { id:"mv-ettin-thug",name:"Ettin Thug",source:"mv",level:8,role:"Brute",xp:350,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:110,ac:20,fort:21,ref:17,will:19,initiative:5,perception:11,speed:"6",powers:[{name:"Double Actions",action:"Trait",description:"The ettin makes two initiative checks and takes a full turn on each initiative result"},{name:"The",action:"Trait",description:"ettin can take two immediate actions per round but only one between one turn and the next"},{name:"Smash",action:"Standard",description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 1d12 + 3 damage."},{name:"Kick",action:"Move",description:"Attack: Melee 1 (one creature); +11 vs. Fortitude Hit: The ettin pushes the target up to 2 squares. The ettin then moves up to half its speed."}],alignment:"Unaligned",languages:["Giant Monster Vault","page(s) 119","Dungeon Magazine 184."] },
  { id:"mv-ettin-wrath-chanter",name:"Ettin Wrath Chanter",source:"mv",level:8,role:"Controller",roleModifier:"Elite",xp:0,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:184,ac:22,fort:21,ref:17,will:20,initiative:5,perception:11,speed:"6",powers:[{name:"Rage Song",action:"Aura",description:"Aura 5 Enemies take a -2 penalty to attack rolls and gain a +2 bonus to damage rolls while in the aura"},{name:"Allies",action:"Trait",description:"gain a +2 bonus to attack rolls and damage rolls while in the aura"},{name:"Double Actions",action:"Trait",description:"The ettin makes two initiative checks and takes a full turn on each initiative result"},{name:"The",action:"Trait",description:"ettin can take two immediate actions per round but only one between one turn and the next"},{name:"Dual Brain At",action:"Trait",description:"the end of each of its turns, the ettin automatically ends any dazing, stunning, or charm effect on itself"},{name:"Smash",action:"Standard",description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d8 + 7 damage, and the target falls prone. Invoke Fury ✦ At-Will Effect: Close burst 5 (one enemy in the burst). The target must use a free action to charge or make a basic attack against a target of the ettin's choice. The movement for this charge does not provoke opportunity attacks."}],alignment:"Unaligned",languages:["Giant Monster Vault","page(s) 119","Dungeon Magazine 184","Dungeon Magazine 218."] },
  { id:"mv-gluttonous-rust-monster",name:"Gluttonous Rust Monster",source:"mv",level:8,role:"Brute",xp:350,size:"Medium",origin:"Natural",type:"Beast",hp:110,ac:20,fort:21,ref:19,will:17,initiative:7,perception:5,speed:"6",senses:["Low-light vision"],powers:[{name:"Rusting Defense Whenever",action:"Trait",description:"an attack using a metal weapon hits the rust monster, the weapon used in the attack is rusting until the end of the encounter"},{name:"While",action:"Trait",description:"the weapon is rusting, attacks with the weapon take a -1 penalty to attack rolls"},{name:"If",action:"Trait",description:"the weapon used to attack the rust monster is already rusting, the penalty to attack rolls worsens by 1 (to a maximum penalty of -5)"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 3d10 + 3 damage. If the target is wearing heavy armor, the armor is rusting until the end of the encounter. While the armor is rusting, the target takes a -1 penalty to AC. If the target is wearing armor that is already rusting, increase the penalty to AC by 1 (to a maximum penalty of -5)."},{name:"Devour Metal",action:"Standard",description:"Recharge if the power misses Attack: Melee 1 (one creature wearing or wielding a rusting item); +11 vs. Reflex Hit: The rusting item is destroyed. If the item was magic, residuum worth the item's market value can be retrieved from the rust monster after the creature is slain."},{name:"Gluttonous Bite",action:"Standard",recharge:"Encounter",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 4d10 + 8 damage. If the target is wearing heavy armor, the armor is rusting until the end of the encounter. While the armor is rusting, the target takes a -1 penalty to AC. If the target is wearing armor that is already rusting, the penalty to AC worsens by 1 (to a maximum penalty of -5). In addition, any weapon the target is wielding is rusting until the end of the encounter. While the weapon is rusting, attacks with the weapon take a -1 penalty to attack rolls. If the weapon is already rusting, the penalty to attack rolls worsens by 1 (to a maximum penalty of -5). Miss: Half damage."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 252","Dungeon Magazine 193."] },
  { id:"mv-gnoll-far-fang",name:"Gnoll Far Fang",source:"mv",level:8,role:"Artillery",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:68,ac:22,fort:20,ref:22,will:19,initiative:9,perception:11,speed:"8",senses:["Low-light vision"],powers:[{name:"Pack Attack",action:"Trait",description:"The gnoll's attacks deal 5 extra damage to any enemy that has two or more of the gnoll's allies adjacent to it"},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6 + 7 damage, or 2d6 + 9 while the gnoll is bloodied."},{name:"Fang Bow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 30 (one or two creatures); +15 vs. AC Hit: 2d10 + 5 damage, or 2d10 + 7 while the gnoll is bloodied."},{name:"Hungry Arrows",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Area burst 2 within 10 (enemies in the burst); +15 vs. AC Hit: 2d10 + 5 damage, or 2d10 + 7 while the gnoll is bloodied. The target takes ongoing 5 damage (save ends). Skills Stealth +14"}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : fang bow (longbow)","handaxe","leather armor . Monster Vault","page(s) 146","Dungeon Magazine 192","Dungeon Magazine 216."] },
  { id:"mv-gnoll-pack-lord",name:"Gnoll Pack Lord",source:"mv",level:8,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:90,ac:22,fort:21,ref:19,will:22,initiative:6,perception:6,speed:"8",senses:["Low-light vision"],powers:[{name:"Pack Attack",action:"Trait",description:"The gnoll's attacks deal 5 extra damage to any enemy that has two or more of the gnoll's allies adjacent to it"},{name:"Flail",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 1d10 + 11 damage."},{name:"Demonic Frenzy",action:"Standard",keywords:["charm"],recharge:"Recharge when an ally drops to 0 hit points",description:"Attack: Ranged 10 (one creature); +11 vs. Will Hit: The target takes a -2 penalty to attack rolls until the end of its next turn. In addition, the target uses a free action to make two basic attacks against a target or targets of the gnoll's choice. Effect: The target is dazed until the end of its next turn."},{name:"Feed on the Weak",action:"Standard",description:"Attack: Area burst 1 within 5 (enemies in the burst); +11 vs. Will Hit: The target grants combat advantage until the start of its next turn. Effect: One ally in the burst can make a basic attack as a free action."},{name:"Pack Cackle",action:"Minor",recharge:"Recharge 4-6",description:"Effect: Close burst 5 (allies in the burst). Each target can shift up to 2 squares as a free action"}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : flail","leather armor . Monster Vault","page(s) 147","Madness at Gardmore Abbey","page(s) 4-28","Dungeon Magazine 192","Dungeon Magazine 214."] },
  { id:"mv-human-duelist",name:"Human Duelist",source:"mv",level:8,role:"Soldier",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:85,ac:24,fort:20,ref:22,will:20,initiative:11,perception:7,speed:"6",powers:[{name:"Duelist's Poise Whenever",action:"Trait",description:"the duelist hits an enemy granting combat advantage to it, the enemy is immobilized until the end of the enemy's next turn"},{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d8 + 7 damage. Effect: The duelist marks the target until the end of the swordsman's next turn."},{name:"Advantageous Jab",action:"Triggered",keywords:["weapon"],description:"Trigger: An enemy marked by the duelist makes an attack that doesn't include it as a target. Attack (Immediate Interrupt): Melee 1 (the triggering enemy); +13 vs. AC Hit: 1d8 + 8 damage. Effect: The target takes a -2 penalty to attack rolls until the end of this turn. Skills Athletics +12"}],alignment:"Unaligned",languages:["Common Equipment : leather armor","longsword . Monster Vault","page(s) 173","The Shadowfell","page(s) E4","Madness at Gardmore Abbey","page(s) 2-17","Dungeon Magazine 200."] },
  { id:"mv-minotaur-soldier",name:"Minotaur Soldier",source:"mv",level:8,role:"Soldier",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:89,ac:24,fort:22,ref:19,will:19,initiative:8,perception:11,speed:"6",powers:[{name:"Battleaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 1d10 + 8 damage, and the minotaur uses shield bash against the same target."},{name:"Shield Bash",action:"Minor",description:"1/round Requirement: The minotaur must be using a shield Attack: Melee 1 (one creature); +11 vs. Fortitude Hit: 1d6 damage, and the target falls prone."},{name:"Goring Toss",action:"Triggered",description:"Trigger: An enemy adjacent to the minotaur shifts. Attack (Immediate Interrupt): Melee 1 (the triggering enemy); +11 vs. Reflex Hit: 1d6 + 5 damage, the target is immobilized until the end of its turn, and the minotaur slides the target up to 2 squares to a square adjacent to the minotaur."}],alignment:"Unaligned",languages:["Common Equipment : battleaxe","heavy shield . Monster Vault","page(s) 208","Dungeon Magazine 189","Madness at Gardmore Abbey","page(s) 4-20","Dungeon Magazine 195","Dungeon Magazine 206","Dungeon Magazine 212."] },
  { id:"mv-ogre-mercenary",name:"Ogre Mercenary",source:"mv",level:8,role:"Soldier",xp:350,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:93,ac:24,fort:22,ref:19,will:19,initiative:8,perception:6,speed:"8",powers:[{name:"Morningstar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d8 + 7 damage. Effect: The ogre marks the target until the end of the ogre's next turn."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +13 vs. AC Hit: 1d8 + 7 damage."},{name:"Brutal Sweep",action:"Standard",keywords:["weapon"],description:"Attack: Close blast 2 (creatures in the blast); +13 vs. AC Hit: 1d8 + 7 damage, and the target falls prone."}],alignment:"Unaligned",languages:["Giant Equipment : handaxe x2","morningstar . Monster Vault","page(s) 218","Madness at Gardmore Abbey","page(s) 3-32","Dungeon Magazine 193","Dungeon Magazine 200","Dungeon Magazine 206","Dungeon Magazine 210","Dungeon Magazine 212","Dungeon Magazine 214","Dungeon Magazine 218."] },
  { id:"mv-shambling-mummy",name:"Shambling Mummy",source:"mv",level:8,role:"Brute",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:104,ac:20,fort:22,ref:17,will:21,initiative:3,perception:5,speed:"4",senses:["Darkvision"],resist:["10 necrotic,","10 poison"],immune:["disease"],powers:[{name:"Flammable Corpus Whenever",action:"Trait",description:"the mummy takes fire damage, it also takes ongoing 5 fire damage (save ends)"},{name:"Rotting Grasp",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +11 vs. Fortitude Hit: 2d8 + 8 necrotic damage, and the target can't regain hit points until the end of the mummy's next turn."},{name:"Warding Curse",action:"Minor",keywords:["necrotic"],description:"Effect: Ranged 10 (one creature). The target takes 5 necrotic damage whenever it attacks until the mummy uses this power again or until the end of the encounter."}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 212","Madness at Gardmore Abbey","page(s) 4-14","Dungeon Magazine 214","Dungeon Magazine 218."] },
  { id:"mv-sovereign-wraith",name:"Sovereign Wraith",source:"mv",level:8,role:"Soldier",xp:350,size:"Medium",origin:"Shadow",type:"Humanoid",keywords:["undead"],hp:89,ac:24,fort:20,ref:22,will:21,initiative:11,perception:6,speed:"0, fly 6 (hover); phasing",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],powers:[{name:"Insubstantial",action:"Trait",description:"The wraith takes half damage from all attacks, except those that deal force damage"},{name:"Whenever",action:"Trait",description:"the wraith takes radiant damage, it loses this trait until the start of its next turn"},{name:"Spawn Wraith",action:"Trait",description:"When the wraith kills a humanoid, that humanoid becomes a wraith figment at the start of this wraith's next turn"},{name:"The",action:"Trait",description:"new wraith appears in the space where the humanoid died or in the nearest unoccupied square, and it rolls a new initiative check"},{name:"The",action:"Trait",description:"new wraith acts under the Dungeon Master's control"},{name:"Spectral Sword",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +11 vs. Fortitude Hit: 2d8 + 2 necrotic damage, and the target grants combat advantage and takes ongoing 5 necrotic damage (save ends both). Effect: The wraith marks the target until the end of the wraith's next turn"},{name:"Lonely Death",action:"Standard",keywords:["illusion"],recharge:"Recharge 3-6",description:"Effect: The wraith uses spectral sword. If the attack hits, all creatures except the wraith are invisible to the target (save ends Skills Stealth +14"}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 287","The Shadowfell","page(s) E9","Dungeon Magazine 187","Dungeon Magazine 214","Dungeon Magazine 218."] },
  { id:"mv-tiefling-occultist",name:"Tiefling Occultist",source:"mv",level:8,role:"Controller",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:87,ac:22,fort:18,ref:20,will:22,initiative:4,perception:5,speed:"6",senses:["Low-light vision"],resist:["10 fire"],powers:[{name:"Hell Rod",action:"Standard",keywords:["fire","implement"],description:"Attack: 1 (one creature); +11 vs. Reflex Hit: 2d6 + 6 fire damage, and ongoing 5 fire damage (save ends)."},{name:"Soul Fire",action:"Standard",keywords:["fear","fire","implement","psychic"],description:"Attack: Area burst 1 within 10 (enemies in the burst); +11 vs. Reflex Hit: Ongoing 10 fire damage (save ends). In addition, the first time the target willingly moves closer to the tiefling before the end of its next turn, the target takes 10 psychic damage. Miss: Ongoing 5 fire damage (save ends)."},{name:"Baleful Teleport",action:"Move",keywords:["teleportation"],recharge:"Recharge 4-6",description:"Effect: Before the attack, the tiefling teleports up to 10 squares Attack: Ranged 10 (one creature); +11 vs. Will Hit: The tiefling teleports the target 10 squares to the square it just left."},{name:"Fiery Transposition",action:"Triggered",keywords:["fire","teleportation"],recharge:"Encounter",description:"Trigger: An enemy hits the tiefling. Effect (Immediate Interrupt): Close burst 3 (creatures in the burst). Each target takes 5 fire damage, and then the tiefling and the triggering enemy teleport, swapping positions. Skills Bluff +14, Stealth +9"}],alignment:"Unaligned",languages:["Common Equipment : leather armor","rod implement . Monster Vault","page(s) 263","Dungeon Magazine 186","Dungeon Magazine 192."] },
  { id:"mv-war-hyena",name:"War Hyena",source:"mv",level:8,role:"Soldier",roleModifier:"Minion",xp:88,size:"Medium",origin:"Natural",type:"Beast",hp:1,ac:24,fort:21,ref:20,will:19,initiative:9,perception:6,speed:"8",senses:["Low-light vision"],powers:[{name:"Harrier",action:"Aura",description:"Aura 1 Any enemy in the aura grants combat advantage."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 8 damage."},{name:"Savage Response",action:"Triggered",description:"Trigger: An enemy adjacent to the hyena makes an attack that doesn't include it as a target. Effect (Immediate Reaction): The hyena uses bite against the triggering enemy."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 298."] },
  { id:"mv-young-owlbear",name:"Young Owlbear",source:"mv",level:8,role:"Brute",xp:350,size:"Large",origin:"Fey",type:"Beast",hp:106,ac:20,fort:21,ref:19,will:20,initiative:6,perception:12,speed:"7",senses:["Darkvision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d6 + 3 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The owlbear uses claw twice. If both attacks hit the same creature, the owlbear grabs it (escape DC 16) if the owlbear has fewer than two creatures grabbed."},{name:"Beak Snap",action:"Standard",description:"Effect: Melee 1 (one creature grabbed by the owlbear). The target takes 2d8 + 11 damage."},{name:"Dazing Hoot",action:"Standard",recharge:"Recharge when first bloodied",description:"Attack: Close blast 3 (creatures in the blast); +11 vs. Fortitude Hit: The target is dazed (save ends)."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 234."] },
  { id:"mv-beholder",name:"Beholder",source:"mv",level:9,role:"Artillery",roleModifier:"Solo",xp:2000,size:"Large",origin:"Aberrant",type:"Magical beast",hp:392,ac:23,fort:21,ref:22,will:22,initiative:9,perception:11,speed:"0, fly 4 (hover) All-around vision",senses:["Darkvision"],powers:[{name:"All-Around Vision",action:"Trait",description:"Enemies can't gain combat advantage by flanking the beholder"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d8 + 8 damage."},{name:"Eye Rays",action:"Standard",description:"Effect: The beholder uses two of the following eye rays, using each against a different target. This attack does not provoke opportunity attacks. 1. Charm Ray (charm): Ranged 10; +14 vs. Will; the target is dominated until the end of its next turn. 2. Wounding Ray (necrotic): Ranged 10; +14 vs. Fortitude; 2d10 + 6 necrotic damage. 3. Sleep Ray (charm): Ranged 10; +14 vs. Will; the target is immobilized (save ends). First Failed Saving Throw: The target is knocked unconscious instead of immobilized (save ends). 4. Telekinesis Ray: Ranged 10; +14 vs. Fortitude; the beholder slides the target up to 4 squares. 5. Slowing Ray (necrotic): Ranged 10; +14 vs. Reflex; 3d6 + 5 necrotic damage, and the target is slowed (save ends). 6. Brilliant Ray (radiant): Ranged 10; +14 vs. Will; 1d6 + 5 radiant damage, and the target is blinded (save ends). 7. Terror Ray (fear, psychic): Ranged 10; +14 vs. Will; 2d8 + 5 psychic damage, and the beholder pushes the target its speed. 8. Petrifying Ray: Ranged 10; +14 vs. Fortitude; the target is petrified (save ends). Aftereffect: The target is immobilized (save ends). 9. Death Ray (necrotic): Ranged 10; +14 vs. Fortitude; 2d8 + 10 necrotic damage. If the target is bloodied before or after the attack, it is also dazed (save ends). First Failed Saving Throw: The target is dazed and weakened (save ends both). Second Failed Saving Throw: The target dies. 10. Disintegrate Ray: Ranged 10; +14 vs. Fortitude; 1d8 + 5 damage, and ongoing 10 damage (save ends)."},{name:"Eye Ray Frenzy",action:"Standard",recharge:"Recharge 5-6",description:"Requirement: The beholder must be bloodied Effect: As eye rays above, except the beholder makes three eye ray attacks."},{name:"Central Eye",action:"Minor",description:"(1/round) Attack: Close blast 5 (enemies in the blast); +12 vs. Will Hit: The target cannot use encounter or daily attack powers until the end of its next turn."},{name:"Random Eye Ray",action:"Triggered",description:"Trigger: The beholder is conscious and an enemy starts its turn within 5 squares of it. Effect (No Action): The beholder uses one random eye ray against the triggering enemy."}],alignment:"Unaligned",languages:["Deep Speech Monster Vault","page(s) 26","Madness at Gardmore Abbey","page(s) 3-28","Dungeon Magazine 192","Dungeon Magazine 196","Dungeon Magazine 206","Dungeon Magazine 214","Dungeon Magazine 216."] },
  { id:"mv-eladrin-battle-dancer",name:"Eladrin Battle Dancer",source:"mv",level:9,role:"Skirmisher",xp:400,size:"Medium",origin:"Fey",type:"Humanoid",hp:94,ac:23,fort:21,ref:22,will:20,initiative:11,perception:5,speed:"6",senses:["Low-light vision"],powers:[{name:"Dancing Blade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d8 + 8 damage, and the eladrin becomes invisible to the target until the end of the eladrin's next turn."},{name:"Battle Dance",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Effect: The eladrin shifts up to its speed. Each time the eladrin enters a square adjacent to an enemy for the first time during the move, it makes a melee basic attack against that enemy."},{name:"Surprise Fey Step",action:"Move",keywords:["teleportation"],recharge:"Recharge 3-6",description:"Effect: The eladrin teleports 5 squares. Until the end of its turn, the eladrin gains combat advantage against each enemy adjacent to its destination square."}],alignment:"Unaligned",languages:["Common","Elven Equipment : chainmail","longsword . Monster Vault","page(s) 115."] },
  { id:"mv-gnoll-demon-spawn",name:"Gnoll Demon Spawn",source:"mv",level:9,role:"Brute",xp:900,size:"Large",origin:"Natural",type:"Humanoid",hp:120,ac:21,fort:23,ref:21,will:20,initiative:7,perception:11,speed:"8",senses:["Low-light vision"],powers:[{name:"Pack Attack",action:"Trait",description:"The gnoll's attacks deal 5 extra damage to any enemy that has two or more of the gnoll's allies adjacent to it"},{name:"Claws",action:"Standard",description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 3d10 + 5 damage."},{name:"Hungry Bite",action:"Minor",description:"1/round Requirement: The gnoll must be bloodied. Attack: Melee 2 (one creature); +14 vs. AC Hit: 1d6 + 6 damage, and the gnoll gains 5 temporary hit points."}],alignment:"Unaligned",languages:["Abyssal","Common Monster Vault","page(s) 147","Madness at Gardmore Abbey","page(s) 4-24","Dungeon Magazine 214","Dungeon Magazine 216."] },
  { id:"mv-minotaur-charger",name:"Minotaur Charger",source:"mv",level:9,role:"Skirmisher",xp:400,size:"Medium",origin:"Natural",type:"Humanoid",hp:94,ac:23,fort:23,ref:21,will:20,initiative:9,perception:10,speed:"6",powers:[{name:"Deft Charge",action:"Trait",description:"While the minotaur is charging, its movement does not provoke opportunity attacks"},{name:"Falchion",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 4d4 + 7 damage."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +14 vs. AC Hit: 2d6 + 7 damage."},{name:"Goring Rush",action:"Triggered",description:"Trigger: An enemy adjacent to the minotaur deals damage to the minotaur. Attack (Immediate Reaction): Melee 1 (the triggering enemy); +12 vs. Fortitude Hit: 1d6 + 5 damage, and the minotaur can push the target 1 square and shift 1 square to the square the target occupied. The minotaur can push the target and shift four more times in this way."}],alignment:"Unaligned",languages:["Common Equipment : falchion","handaxe x4. Monster Vault","page(s) 209","Dungeon Magazine 186","Madness at Gardmore Abbey","page(s) 4-20","Dungeon Magazine 195","Dungeon Magazine 214."] },
  { id:"mv-minotaur-magus",name:"Minotaur Magus",source:"mv",level:9,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:96,ac:23,fort:21,ref:20,will:23,initiative:5,perception:12,speed:"6",powers:[{name:"Unleash the Beast Within",action:"Aura",description:"Aura 3 Any ally that starts its turn in the aura gains a +2 power bonus to attack rolls and damage rolls on attacks made as part of charges until the end of that ally's turn."},{name:"Glaive",action:"Standard",description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 2d4 + 10 damage, and the magus slides the target up to 2 squares. Miss: The magus can slide the target 1 square."},{name:"Baphomet's Rage",action:"Standard",keywords:["charm","psychic"],description:"Attack: Ranged 10 (one creature); +12 vs. Will Hit: 1d6 + 4 psychic damage, and the target uses a free action to charge a creature of the magus's choosing."},{name:"Crimson Bolt",action:"Standard",keywords:["fire","lightning"],recharge:"Recharge 4-6",description:"Attack: Ranged 20 (one creature); +12 vs. Reflex Hit: 2d10 + 5 lightning damage, and the target takes ongoing 5 fire damage and cannot shift (save ends both)."},{name:"Goring Fling",action:"Triggered",description:"Trigger: An enemy adjacent to the magus deals damage to the magus. Attack (Immediate Reaction): Melee 1 (the triggering enemy); +12 vs. Fortitude Hit: 1d6 + 4 damage, and the magus pushes the target up to 3 squares. Skills Bluff +14, Insight +12"}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : glaive . Monster Vault","page(s) 210","Dungeon Magazine 189","Madness at Gardmore Abbey","page(s) 4-22","Dungeon Magazine 206."] },
  { id:"mv-trained-owlbear",name:"Trained Owlbear",source:"mv",level:9,role:"Soldier",xp:400,size:"Large",origin:"Fey",type:"Beast",hp:96,ac:24,fort:23,ref:22,will:20,initiative:8,perception:7,speed:"7",senses:["Darkvision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 2d8 + 8 damage."},{name:"Thunderous Shriek",action:"Standard",keywords:["thunder"],recharge:"Recharge 4-6",description:"Attack: Close burst 2 (creatures in the burst); +12 vs. Fortitude Hit: 4d6 + 5 thunder damage, and the target is knocked prone."},{name:"Guardian Claw",action:"Triggered",description:"Trigger: An enemy adjacent to the trained owlbear makes an attack that does not include it. Attack (Opportunity Action): Melee 1 (the triggering enemy); +14 vs. AC Hit: 2d8 + 8 damage. Miss: 5 damage."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 236","Dungeon Magazine 192."] },
  { id:"mv-bramblewood-treant",name:"Bramblewood Treant",source:"mv",level:10,role:"Soldier",xp:500,size:"Large",origin:"Fey",type:"Magical beast",keywords:["plant"],hp:108,ac:26,fort:23,ref:20,will:24,initiative:9,perception:11,speed:"8 (forest walk)",senses:["Low-light vision"],powers:[{name:"Bramble Branches",action:"Aura",description:"Aura 2 Enemies treat squares within the aura as difficult terrain"},{name:"Wooden Body Whenever",action:"Trait",description:"the treant takes fire damage, it also takes ongoing 5 fire damage (save ends)"},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +15 vs. AC Hit: 1d12 + 12 damage. Effect: The treant marks the target until the end of the treant's next turn."},{name:"Throw Stone",action:"Standard",description:"Attack: Ranged 20 (one creature); +15 vs. AC Hit: 2d6 + 7 damage."},{name:"Entangling Branch",action:"Triggered",description:"Trigger: An enemy within 2 squares of the treant moves. Attack (Immediate Interrupt): Melee 2 (the triggering enemy); +13 vs. Reflex Hit: The treant grabs the target (escape DC 18)."}],alignment:"Unaligned",languages:["Elven Monster Vault","page(s) 265."] },
  { id:"mv-charnel-otyugh",name:"Charnel Otyugh",source:"mv",level:10,role:"Soldier",roleModifier:"Elite",xp:1000,size:"Large",origin:"Natural",type:"Beast",hp:212,ac:26,fort:27,ref:21,will:24,initiative:7,perception:13,speed:"5, swim 5",senses:["Darkvision"],resist:["5 necrotic"],powers:[{name:"Otyugh Stench",action:"Aura",description:"Aura 1 Living enemies take a -2 penalty to attack rolls while in the aura."},{name:"Charnel Lash",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 3 (one creature); +15 vs. AC Hit: 1d8 + 8 damage, and ongoing 5 necrotic damage (save ends). The otyugh pulls the target up to 2 squares and grabs it (escape DC 18)."},{name:"Rotting Bite",action:"Standard",keywords:["disease","necrotic"],description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d12 + 6 necrotic damage, and ongoing 5 necrotic damage (save ends). In addition, at the end of the encounter, the target makes a saving throw. On a failure, the target contracts greater otyugh filth fever (stage 1)."},{name:"Charnel Frenzy",action:"Standard",keywords:["necrotic"],recharge:"Recharge 4-6",description:"Attack: Close burst 3 (enemies in the burst); +15 vs. AC Hit: 1d8 + 8 damage, and ongoing 5 necrotic damage (save ends)."},{name:"Life Leech",action:"Minor",keywords:["healing","necrotic"],description:"1/round Attack: Melee 3 (one creature grabbed by the otyugh); +13 vs. Fortitude Hit: 10 necrotic damage, and the otyugh regains 5 hit points. Skills Stealth +10"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 232","Dungeon Magazine 183","Dungeon Magazine 214."] },
  { id:"mv-elder-vampire-spawn",name:"Elder Vampire Spawn",source:"mv",level:10,role:"Soldier",roleModifier:"Minion",xp:125,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:1,ac:26,fort:23,ref:22,will:20,initiative:11,perception:12,speed:"7, climb 4 (spider climb)",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],powers:[{name:"Destroyed",action:"Trait",description:"by Sunlight Whenever the vampire starts its turn in direct sunlight, it can take only a single move action during its turn"},{name:"If",action:"Trait",description:"it ends that turn in direct sunlight, it turns to ash and is destroyed"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 8 damage, and the vampire grabs the target (escape DC 18) if it does not have a creature grabbed."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the vampire); +15 vs. AC. If the target is dazed, the attack hits automatically Hit: 10 damage, and the target is dazed until the grab ends."}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 281","Madness at Gardmore Abbey","page(s) 4-19","Dungeon Magazine 207."] },
  { id:"mv-ettin-hunter",name:"Ettin Hunter",source:"mv",level:10,role:"Artillery",xp:500,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:86,ac:24,fort:23,ref:19,will:20,initiative:6,perception:12,speed:"6",powers:[{name:"Double Actions",action:"Trait",description:"The ettin makes two initiative checks and takes a full turn on each initiative result"},{name:"The",action:"Trait",description:"ettin can take two immediate actions per round but only one between one turn and the next"},{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +15 vs. AC Hit: 1d6 + 6 damage."},{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +17 vs. AC Hit: 1d6 + 6 damage."},{name:"Pinion",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Ranged 20 (one creature); +17 vs. AC Hit: 2d6 + 7 damage, and the target is restrained until it escapes (DC 18) or teleports."}],alignment:"Unaligned",languages:["Giant Equipment : javelin x10. Monster Vault","page(s) 120","Dungeon Magazine 218."] },
  { id:"mv-hydra",name:"Hydra",source:"mv",level:10,role:"Brute",roleModifier:"Solo",xp:2500,size:"Large",origin:"Natural",type:"Beast",keywords:["reptile","water"],hp:432,ac:24,fort:23,ref:21,will:21,initiative:8,perception:13,speed:"5, swim 10 All-around vision",senses:["Darkvision"],powers:[{name:"All-Around Vision",action:"Trait",description:"Enemies can't gain combat advantage by flanking the hydra"},{name:"Many Headed",action:"Trait",description:"While stunned or dominated, the hydra can take free actions"},{name:"Regenerating Heads",action:"Trait",description:"The hydra starts an encounter with four heads"},{name:"When",action:"Trait",description:"the hydra's hit points first go below 324, 216, and 108, one of its heads is destroyed"},{name:"Whenever",action:"Trait",description:"a head is destroyed, the hydra grows two heads at the start of its next turn unless it takes fire or acid damage before then"},{name:"Threatening Reach",action:"Trait",description:"The hydra can make opportunity attacks against enemies within 2 squares of it"},{name:"Bite",action:"Standard",description:"Attack: Melee 2 (one creature); +15 vs. AC Hit: 3d10 damage."},{name:"Hydra Fury",action:"Standard",description:"Effect: The hydra uses bite a number of times equal to the number of heads it currently has. If it has only two heads, it gains a +5 bonus to damage rolls with bite. If it has only one head, it gains a +15 bonus to damage rolls with bite."},{name:"Snapping Jaws",action:"Triggered",description:"Trigger: An enemy ends its turn within 2 squares of the hydra. Effect (Free Action): The hydra uses bite twice against the triggering enemy. Skills Stealth +13"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 174."] },
  { id:"mv-impaling-roper",name:"Impaling Roper",source:"mv",level:10,role:"Lurker",xp:500,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["earth"],hp:84,ac:24,fort:23,ref:22,will:19,initiative:13,perception:9,speed:"2, climb 2 (spider climb)",senses:["Darkvision"],resist:["20 to all damage from any of the target's attacks. While the target is grabbed, any creature can attack the tentacle in the target's square. The tentacle uses the roper's defenses. An attack against a tentacle does not deal damage or otherwise affect the roper, but on a hit, the grab ends. ⚔ Impale ✦ At-Will Attack: Melee","10 (one creature grabbed by the roper)","+13 vs. Reflex Effect: The roper pulls the target up to","10 squares to a square adjacent to it. Hit:","4d10 +","5 damage, and the grab ends. Miss: Half damage, and the grab ends. Skills Stealth +14"],powers:[{name:"Tentacle",action:"Standard",description:"Attack: Melee 10 (one creature); +13 vs. Reflex Hit: 1d8 + 5 damage. Effect: The roper grabs the target (escape DC 26). Until the end of the roper's next turn, the roper gains resist 20 to all damage from any of the target's attacks. While the target is grabbed, any creature can attack the tentacle in the target's square. The tentacle uses the roper's defenses. An attack against a tentacle does not deal damage or otherwise affect the roper, but on a hit, the grab ends."},{name:"Impale",action:"Standard",description:"Attack: Melee 10 (one creature grabbed by the roper); +13 vs. Reflex Effect: The roper pulls the target up to 10 squares to a square adjacent to it. Hit: 4d10 + 5 damage, and the grab ends. Miss: Half damage, and the grab ends. Skills Stealth +14"}],alignment:"Unaligned",languages:["Primordial Monster Vault","page(s) 247."] },
  { id:"mv-manticore-striker",name:"Manticore Striker",source:"mv",level:10,role:"Skirmisher",xp:500,size:"Large",origin:"Natural",type:"Magical beast",hp:106,ac:24,fort:23,ref:23,will:20,initiative:12,perception:13,speed:"6, fly 8",powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d10 + 7 damage, or 2d10 + 10 with a charge attack. Effect: After the attack, the manticore shifts up to 2 squares."},{name:"Tail Spike",action:"Standard",description:"Attack: Ranged 10 (one creature); +15 vs. AC Hit: 2d8 + 4 damage. Effect: After the attack, the manticore shifts up to 2 squares."},{name:"Spike Counterattack",action:"Triggered",description:"Trigger: An enemy hits the manticore. Effect (Immediate Reaction): The manticore uses tail spike against the triggering enemy. This attack does not provoke opportunity attacks."}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 198."] },
  { id:"mv-mesmeric-eye-basilisk",name:"Mesmeric-Eye Basilisk",source:"mv",level:10,role:"Soldier",xp:500,size:"Large",origin:"Natural",type:"Beast",keywords:["reptile"],hp:109,ac:26,fort:22,ref:20,will:24,initiative:8,perception:7,speed:"4",powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d12 + 5 damage."},{name:"Mesmerizing Gaze",action:"Standard",keywords:["charm","psychic"],description:"Attack: Close blast 3 (creatures in the blast); +13 vs. Will Hit: 2d8 + 7 psychic damage, and the basilisk pulls the target up to 2 squares. Effect: The basilisk marks the target until the end of the basilisk's next turn."},{name:"Mesmeric Punishment",action:"Triggered",keywords:["charm"],description:"Trigger: An enemy marked by and within 5 squares of the basilisk makes an attack that does not include it as a target. Attack (Immediate Interrupt): Close burst 5 (the triggering enemy); +13 vs. Will Hit: The target takes a -2 penalty to the triggering attack roll and is dazed (save ends)."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 21."] },
  { id:"mv-moldering-mummy",name:"Moldering Mummy",source:"mv",level:10,role:"Brute",roleModifier:"Minion",xp:125,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:1,ac:22,fort:24,ref:19,will:23,initiative:4,perception:6,speed:"4",senses:["Darkvision"],resist:["10 necrotic,","10 poison"],immune:["disease"],powers:[{name:"Clutch of the Dead",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. Fortitude Hit: 11 damage, and the mummy grabs the target (escape DC 18) if it does not have a creature grabbed."},{name:"Final Curse",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy's attack that does not deal fire damage reduces the mummy to 0 hit points. Attack (No Action): Ranged 10 (the triggering enemy); +13 vs. Will Hit: The target regains half the normal number of hit points from the next healing surge it spends."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 213."] },
  { id:"mv-ogre-juggernaut",name:"Ogre Juggernaut",source:"mv",level:10,role:"Brute",xp:500,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:131,ac:22,fort:24,ref:20,will:20,initiative:7,perception:7,speed:"8",powers:[{name:"Greatclub",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +15 vs. AC Hit: 4d8 + 5 damage."},{name:"Rock",action:"Standard",description:"Attack: Ranged 5 (one creature); +15 vs. AC Hit: 3d6 + 7 damage."},{name:"Juggernaut Push",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +13 vs. Fortitude Hit: The ogre pushes the target 1 square and knocks it prone. The ogre then shifts 1 square to the square the target vacated. The ogre can push the target an additional number of squares equal to the ogre's speed, shifting an equal number of squares and remaining adjacent to it. The target takes 1d8 damage for each additional square the ogre pushes it."}],alignment:"Unaligned",languages:["Giant Equipment : rock x4","greatclub . Monster Vault","page(s) 219","Dungeon Magazine 214","Dungeon Magazine 218","Dungeon Magazine 221."] },
  { id:"mv-stirge-suckerling-swarm",name:"Stirge Suckerling Swarm",source:"mv",level:10,role:"Brute",xp:500,size:"Medium",origin:"Natural",type:"Beast",keywords:["swarm"],hp:128,ac:22,fort:22,ref:22,will:20,initiative:9,perception:7,speed:"2, fly 6",senses:["Darkvision"],resist:["half damage from melee and ranged attacks"],vulnerable:["5 to close and area attacks"],powers:[{name:"Blood Frenzy",action:"Aura",description:"Aura 1 Any enemy that starts its turn in the aura takes ongoing 5 damage (save ends)"},{name:"If",action:"Trait",description:"that enemy is already taking untyped ongoing damage, that damage increases by 5"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for at least one of the creatures it comprises"},{name:"Swarm of Suckerlings",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 3d6 + 1 damage, and ongoing 5 damage (save ends)."},{name:"Hungry Flight",action:"Triggered",description:"Trigger: An enemy moves away from the swarm. Effect (Immediate Reaction): The swarm flies up to its fly speed to the triggering enemy's square or a square adjacent to that enemy. This movement does not provoke opportunity attacks. Skills Stealth +14"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 261","Dungeon Magazine 187","Dungeon Magazine 198."] },
  { id:"mv-vampire-night-witch",name:"Vampire Night Witch",source:"mv",level:10,role:"Controller",xp:500,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:98,ac:24,fort:20,ref:22,will:24,initiative:9,perception:12,speed:"7, climb 4 (spider climb)",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Burned",action:"Trait",description:"by Sunlight (radiant) Whenever the vampire starts its turn in direct sunlight, it takes 5 radiant damage"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 4d6 + 4 damage. Effect: The vampire slides the target up to 3 squares."},{name:"Bite",action:"Standard",keywords:["healing"],description:"Attack: Melee 1 (one dazed, dominated, stunned, or unconscious creature); +15 vs. AC Hit: 3d10 + 10 damage, and the vampire regains 15 hit points."},{name:"Dream Lure",action:"Standard",keywords:["charm","psychic"],description:"Attack: Ranged 5 (one creature); +13 vs. Will Hit: 3d6 + 4 psychic damage, and the target is dazed until the end of its next turn. Effect: The vampire pulls the target up to 3 squares."},{name:"Vanish into Shadow",action:"Triggered",keywords:["illusion"],recharge:"Encounter",description:"Trigger: The vampire takes damage while bloodied. Effect (No Action): The vampire becomes invisible until the end of the encounter or until it attacks. Skills Acrobatics +14, Athletics +13, Bluff +16, Insight +12, Stealth +14"}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 282","Dungeon Magazine 214","Dungeon Magazine 218."] },
  { id:"mv-demonic-savage-minotaur",name:"Demonic Savage Minotaur",source:"mv",level:11,role:"Brute",xp:600,size:"Large",origin:"Natural",type:"Humanoid",hp:140,ac:23,fort:25,ref:22,will:20,initiative:8,perception:7,speed:"8",powers:[{name:"Claws",action:"Standard",description:"Attack: Melee 2 (one or two creatures); +16 vs. AC. If the minotaur targets only one creature, it can make this attack twice against that creature Hit: 2d6 + 5 damage, and the minotaur grabs the target (escape DC 19) if it has fewer than two creatures grabbed."},{name:"Impale",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the minotaur); +14 vs. Fortitude Hit: 5d8 + 13 damage. The target falls prone and is no longer grabbed by the minotaur."},{name:"Goring Assault",action:"Triggered",description:"Trigger: An enemy within 10 squares of the minotaur hits it with a ranged or area attack. Effect (Immediate Reaction): The minotaur charges the triggering enemy."}],alignment:"Unaligned",languages:["Abyssal","Common Monster Vault","page(s) 211","Dungeon Magazine 184","Dungeon Magazine 189","Madness at Gardmore Abbey","page(s) 4-25","Dungeon Magazine 195","The Book of Vile Darkness","page(s) 2-88."] },
  { id:"mv-doppelganger-infiltrator",name:"Doppelganger Infiltrator",source:"mv",level:11,role:"Lurker",xp:600,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["shapechanger"],hp:90,ac:25,fort:21,ref:25,will:23,initiative:15,perception:6,speed:"6",powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 2d4 + 6 damage. Perfect Replica (illusion, polymorph) ✦ At-Will Effect: Melee 1 (one Medium creature). The doppelganger takes on the form of the target and alters its clothing and gear to match those of the target. Until the end of the doppelganger's next turn, the target is immobilized and takes 6d8 extra damage from the doppelganger's dagger power. See also replica switch."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"polymorph Effect: The doppelganger alters its physical form to appear as a Medium humanoid until it uses change shape again or until it drops to 0 hit points. To assume a specific individual's form, the doppelganger must have seen that individual. Other creatures can make a DC 32 Insight check to discern that the form is a disguise."},{name:"Replica Switch",action:"Triggered",description:"Requirement: The doppelganger must be adjacent to an enemy affected by its perfect replica Trigger: A melee or ranged attack from an enemy unaffected by the doppelganger's perfect replica targets the doppelganger. Effect (Opportunity Action): The doppelganger and the enemy affected by its perfect replica swap places, and the triggering attack instead targets the enemy affected by the doppelganger's perfect replica. Skills Bluff +14, Insight +11, Stealth +16"}],alignment:"Unaligned",languages:["Common Equipment : dagger . Monster Vault","page(s) 62","Dungeon Magazine 200."] },
  { id:"mv-gargoyle-rock-hurler",name:"Gargoyle Rock Hurler",source:"mv",level:11,role:"Artillery",xp:600,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["earth"],hp:87,ac:25,fort:21,ref:19,will:19,initiative:9,perception:13,speed:"6, fly 8",senses:["Darkvision"],resist:["10 to all damage from attacks originating at least","5 squares away from it."],powers:[{name:"Stone Defense",action:"Trait",description:"The gargoyle has resist 10 to all damage from attacks originating at least 5 squares away from it"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 2d8 + 8 damage."},{name:"Hurled Stone",action:"Standard",description:"Attack: Ranged 20 (one creature); +18 vs. AC Hit: 3d6 + 9 damage."},{name:"Hail of Hurled Stone",action:"Standard",description:"Attack: Area burst 1 within 10 (creatures in the burst); +18 vs. AC Hit: 2d6 + 7 damage, or 2d6 + 12 against a target in the burst's origin square. Miss: Half damage. Skills Stealth +14"}],alignment:"Unaligned",languages:["Primordial Equipment : stone x10 Monster Vault","page(s) 123","Dungeon Magazine 186","Dungeon Magazine 198."] },
  { id:"mv-manticore-impaler",name:"Manticore Impaler",source:"mv",level:11,role:"Brute",xp:600,size:"Large",origin:"Natural",type:"Magical beast",hp:138,ac:23,fort:23,ref:23,will:20,initiative:11,perception:14,speed:"6, fly 8",powers:[{name:"Hindered Takeoff",action:"Trait",description:"While the manticore is grabbing a creature, it can't fly higher than 6 squares above the ground"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 3d10 + 8 damage."},{name:"Tail Lance",action:"Standard",description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 2d8 + 6 damage, and the manticore grabs the target (escape DC 19) if it does not have a creature grabbed. Until the grab ends, the target takes ongoing 5 damage."},{name:"Tail Spike",action:"Standard",description:"Attack: Ranged 10 (one creature); +16 vs. AC Hit: 2d8 + 6 damage."},{name:"Prepare to Drop",action:"Move",description:"Effect: The manticore flies up to half its speed and pulls a creature it has grabbed with it. This movement does not provoke opportunity attacks from the grabbed creature, and the manticore can pull the grabbed creature vertically."}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 198."] },
  { id:"mv-mummy-tomb-guardian",name:"Mummy Tomb Guardian",source:"mv",level:11,role:"Soldier",xp:600,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:111,ac:27,fort:24,ref:21,will:23,initiative:6,perception:6,speed:"5",senses:["Darkvision"],resist:["10 necrotic,","10 poison"],immune:["disease"],vulnerable:["5 radiant"],powers:[{name:"Flammable Corpus",action:"Trait",description:"When the mummy takes fire damage, it also takes ongoing 5 fire damage (save ends)"},{name:"Khopesh",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 2d8 + 10 damage, and the target cannot shift (save ends)."},{name:"Curse of No Escape",action:"Minor",description:"Effect: Ranged 10 (one creature). The target is slowed until the mummy curses a different creature or the mummy is destroyed."},{name:"Overwhelming Fear",action:"Triggered",keywords:["fear"],recharge:"Encounter",description:"Trigger: An enemy within 10 squares gains line of sight to any tomb guardian for the first time this encounter.Attack (No Action): Ranged 10 (the triggering enemy); +14 vs. Will. Hit: The target is stunned until the end of the tomb guardian's next turn."}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 213","Dungeon Magazine 218."] },
  { id:"mv-neo-otyugh",name:"Neo-Otyugh",source:"mv",level:11,role:"Controller",roleModifier:"Elite",xp:1200,size:"Huge",origin:"Aberrant",type:"Magical beast",hp:232,ac:25,fort:26,ref:20,will:23,initiative:6,perception:14,speed:"7, swim 7",senses:["Darkvision"],powers:[{name:"Otyugh Stench",action:"Aura",description:"Aura 2 Living enemies take a -2 penalty to attack rolls while in the aura"},{name:"Threatening Reach",action:"Trait",description:"The neo-otyugh can make opportunity attacks against enemies within 4 squares of it"},{name:"Tentacle",action:"Standard",description:"Attack: Melee 4 (one creature); +16 vs. AC Hit: 3d6 + 9 damage, and the neo-otyugh pulls the target up to 3 squares and grabs the target (escape DC 19)."},{name:"Massive Maw of Decay",action:"Standard",keywords:["disease","necrotic"],description:"Attack: Close blast 2 (creatures in the blast); +16 vs. AC Hit: 2d6 + 7 damage, or 2d6 + 10 against a creature grabbed by the neo-otyugh, and ongoing 5 necrotic damage (save ends). In addition, at the end of the encounter, the target makes a saving throw. On a failure, the target contracts greater otyugh filth fever (stage 1)."},{name:"Disgusting Lure",action:"Minor",keywords:["charm","psychic"],description:"Attack: Ranged 20 (one creature); +14 vs. Will Hit: 2d8 psychic damage, and if the target does not end its next turn adjacent to the neo-otyugh, the target takes 15 psychic damage."},{name:"Body Shield",action:"Triggered",description:"Trigger: An enemy hits the neo-otyugh while the neo-otyugh has a creature grabbed. Attack (Immediate Interrupt): Melee 1 (one creature grabbed by the neo-otyugh); +14 vs. Fortitude Hit: The triggering enemy's attack hits the grabbed creature instead of the neo-otyugh. Skills Stealth +16"}],alignment:"Unaligned",languages:["telepathy 10 Monster Vault","page(s) 233","Dungeon Magazine 215."] },
  { id:"mv-savage-displacer-beast",name:"Savage Displacer Beast",source:"mv",level:11,role:"Brute",xp:600,size:"Large",origin:"Fey",type:"Magical beast",hp:136,ac:23,fort:23,ref:25,will:21,initiative:10,perception:8,speed:"8",senses:["Low-light vision"],powers:[{name:"Displacement",action:"Trait",keywords:["illusion"],description:"When a melee or a ranged attack hits the displacer beast, if the player rolled an odd number on the attack roll, the attack misses"},{name:"If",action:"Trait",description:"the player rolled an even number on the attack roll, the attack hits as normal, and the beast loses this trait until the start of its next turn"},{name:"Threatening Reach",action:"Trait",description:"The displacer beast can make opportunity attacks against enemies within 2 squares of it"},{name:"Tentacle",action:"Standard",description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 4d8 + 3 damage, and the displacer beast can push the target 1 square."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 3d10 + 8 damage."},{name:"Brutal Tactics",action:"Triggered",description:"Trigger: An enemy misses the displacer beast with a melee attack. Effect (Free Action): The displacer beast pushes the triggering enemy 1 square. Skills Stealth +15"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 58."] },
  { id:"mv-wilt-eye-basilisk",name:"Wilt-Eye Basilisk",source:"mv",level:11,role:"Controller",xp:600,size:"Large",origin:"Natural",type:"Beast",keywords:["reptile"],hp:117,ac:25,fort:25,ref:21,will:23,initiative:7,perception:11,speed:"4",powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 2d8 + 10 damage."},{name:"Enervating Gaze",action:"Standard",description:"Attack: Area burst 1 within 5 (creatures in the burst); +14 vs. Fortitude Hit: The target takes a -2 penalty to attack rolls (save ends). First Failed Saving Throw: The target falls unconscious (save ends). Miss: The target takes a -2 penalty to attack rolls until the end of the basilisk's next turn. Skills Stealth +12"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 22."] },
  { id:"mv-wind-claw-owlbear",name:"Wind-Claw Owlbear",source:"mv",level:11,role:"Controller",roleModifier:"Elite",xp:1200,size:"Large",origin:"Fey",type:"Beast",keywords:["air"],hp:228,ac:25,fort:25,ref:21,will:23,initiative:8,perception:14,speed:"7",senses:["Darkvision"],powers:[{name:"Keening Gale",action:"Aura",description:"Aura 2 Any enemy that ends its turn in the aura takes 5 damage, and the owlbear slides it up to 2 squares as a free action."},{name:"Wind Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 3d6 + 8 damage, and the owlbear slides the target up to 2 squares and knocks it prone. Miss: The owlbear can slide the target 1 square."},{name:"Disembowel",action:"Standard",description:"Effect: The owlbear uses wind claw twice against one creature. If both attacks hit, that creature is stunned until the end of the owlbear's next turn."},{name:"Beak Snap",action:"Standard",description:"Effect: Melee 1 (one creature stunned by the owlbear). The target takes 4d10 + 16 damage."},{name:"Wind Howl",action:"Triggered",recharge:"Encounter",description:"Trigger: The owlbear is first bloodied. Attack (Immediate Reaction): Close blast 5 (creatures in the blast); +14 vs. Fortitude Hit: The owlbear pushes the target up to 3 squares and knocks it prone. Miss: The owlbear can push the target 1 square."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 237","Dungeon Magazine 198."] },
  { id:"mv-basilisk",name:"Basilisk",source:"mv",level:12,role:"Controller",xp:700,size:"Large",origin:"Natural",type:"Beast",keywords:["reptile"],hp:126,ac:26,fort:26,ref:22,will:22,initiative:7,perception:13,speed:"4",immune:["petrification"],powers:[{name:"Baleful Gaze",action:"Aura",description:"Aura 5 Any enemy in the aura that attacks the basilisk is slowed until the end of that enemy's next turn."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d12 + 7 damage."},{name:"Petrifying Gaze",action:"Standard",description:"Attack: Close blast 3 (creatures in the blast); +15 vs. Fortitude Hit: The target is immobilized (save ends). First Failed Saving Throw: The target is restrained instead of immobilized (save ends). Second Failed Saving Throw: The target is petrified. Miss: The target is slowed until the end of the basilisk's next turn. Skills Stealth +12"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 23."] },
  { id:"mv-battle-troll",name:"Battle Troll",source:"mv",level:12,role:"Soldier",xp:700,size:"Large",origin:"Natural",type:"Humanoid",hp:124,ac:28,fort:26,ref:24,will:22,initiative:12,perception:8,speed:"7",powers:[{name:"Regeneration",action:"Trait",description:"The troll regains 5 hit points whenever it starts its turn and has at least 1 hit point"},{name:"When",action:"Trait",description:"the troll takes fire or acid damage, its regeneration does not function on its next turn. Troll Healing (healing) Whenever an attack that doesn't deal acid or fire damage reduces the troll to 0 hit points, the troll does not die and instead falls unconscious until the start of its next turn, when it returns to life with 15 hit points"},{name:"If",action:"Trait",description:"an attack hits the troll and deals any acid or fire damage while the troll is unconscious, it does not return to life in this way"},{name:"Broadsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +17 vs. AC Hit: 2d12 + 8 damage. If the attack bloodies the target, the troll uses broadsword against it again. Effect: The troll marks the target until the end of the troll's next turn."},{name:"Sweeping Strike",action:"Standard",keywords:["weapon"],description:"Attack: Close blast 2 (enemies in the blast); +17 vs. AC Hit: 2d12 + 5 damage, and the target falls prone."}],alignment:"Unaligned",languages:["Common","Giant Equipment : broadsword","scale armor . Monster Vault","page(s) 273","Dungeon Magazine 185."] },
  { id:"mv-cave-roper",name:"Cave Roper",source:"mv",level:12,role:"Controller",roleModifier:"Elite",xp:1400,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["earth"],hp:252,ac:26,fort:26,ref:21,will:23,initiative:7,perception:9,speed:"2, climb 2 (spider climb)",senses:["Darkvision"],powers:[{name:"Tentacle Release Before",action:"Trait",description:"a creature makes an attack roll against the roper, it can choose to target one of the roper's tentacles"},{name:"The",action:"Trait",description:"tentacles use the same defenses as the roper"},{name:"If",action:"Trait",description:"the attack hits, it does not deal damage or otherwise affect the roper, but one of the roper's grabs end (of the attacker's choice)"},{name:"Stony Body",action:"Trait",description:"The roper can retract its tentacles and closes its eye and mouth to resembles a natural rock formation"},{name:"While",action:"Trait",description:"the roper is on a horizontal rock surface, a creature must succeed at a DC 28 Perception check to see through the roper's disguise"},{name:"Tentacle",action:"Standard",description:"Requirement: The roper must have fewer than two creatures grabbed. Attack: Melee 10 (one creature); +15 vs. Reflex Hit: 2d8 + 9 damage, and the roper grabs the target (escape DC 20). Until the grab ends, the target is weakened."},{name:"Double Attack",action:"Standard",description:"Effect: The roper uses tentacle twice."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the roper); +17 vs. AC Hit: 4d12 + 12 damage. Miss: Half damage."},{name:"Reel",action:"Minor",description:"(1/round) Attack: Melee 10 (each creature grabbed by the roper); +17 vs. Fortitude Hit: The roper pulls the target up to 5 squares. Skills Stealth +12"}],alignment:"Unaligned",languages:["Primordial Monster Vault","page(s) 248","Dungeon Magazine 188","Dungeon Magazine 197."] },
  { id:"mv-cave-spider",name:"Cave Spider",source:"mv",level:12,role:"Skirmisher",roleModifier:"Minion",xp:175,size:"Medium",origin:"Natural",type:"Beast",keywords:["spider"],hp:1,ac:26,fort:24,ref:25,will:22,initiative:15,perception:11,speed:"6, climb 6 (spider climb)",senses:["Darkvision"],resist:["10 poison"],powers:[{name:"Web Walk",action:"Trait",description:"The spider ignores difficult terrain composed of webs"},{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 10 damage, plus 5 poison damage if the target is immobilized, restrained, stunned, or unconscious."},{name:"Tethering Web",action:"Minor",description:"Attack: Ranged 10 (one creature); +15 vs. Reflex Hit: The target is immobilized until the end of its next turn. Skills Athletics +17, Stealth +18"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 303","Dungeon Magazine 185."] },
  { id:"mv-deathbringer-dracolich",name:"Deathbringer Dracolich",source:"mv",level:12,role:"Controller",roleModifier:"Solo",xp:3500,size:"Large",origin:"Natural",type:"Magical beast",keywords:["dragon","undead"],hp:492,ac:26,fort:26,ref:24,will:24,initiative:10,perception:14,speed:"6, fly 8 (clumsy)",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["10 radiant"],powers:[{name:"Action Recovery Whenever",action:"Trait",description:"the dragon ends its turn, any dazing, stunning, or dominating effect on it ends"},{name:"Instinctive Domination On",action:"Trait",description:"an initiative of 10 + its initiative check, the dragon can use a free action to use mesmerizing glance"},{name:"This",action:"Trait",description:"attack does not provoke opportunity attacks"},{name:"If",action:"Trait",description:"the dragon cannot use a free action to make this attack due to a dominating or stunning effect, then that effect ends instead of the dragon making the attack"},{name:"Bite",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 2 (one creature); +17 vs. AC Hit: 2d10 + 9 damage, and ongoing 10 necrotic damage (save ends)."},{name:"Claws",action:"Standard",description:"Attack: Melee 2 (one or two creatures); +17 vs. AC. If the dragon targets only one creature, it can make this attack twice against that creature Hit: 3d6 + 9 damage. Effect: The dracolich slides the target up to 2 squares."},{name:"Breath Weapon",action:"Standard",keywords:["necrotic"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +15 vs. Reflex Hit: 3d12 + 8 necrotic damage, and the target is weakened (save ends). Miss: Half damage, and the target is weakened until the end of its next turn."},{name:"Mesmerizing Glance",action:"Minor",keywords:["charm","psychic"],description:"(1/round) Attack: Ranged 10 (one creature); +15 vs. Will Hit: The target is dominated (save ends). Miss: If the target willingly moves to a square nearer to or adjacent to the dracolich before the end of its next turn, it takes 15 psychic damage. Effect: The dracolich slides the target up to 2 squares."},{name:"Bloodied Breath",action:"Triggered",recharge:"Encounter",description:"Trigger: The dragon is first bloodied. Effect (Free Action): Breath weapon recharges, and the dragon uses it. Skills Insight +14"}],alignment:"Unaligned",languages:["Common","Draconic Monster Vault","page(s) 72."] },
  { id:"mv-dretch-lackey",name:"Dretch Lackey",source:"mv",level:12,role:"Brute",roleModifier:"Minion",xp:250,size:"Small",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:1,ac:24,fort:26,ref:24,will:22,initiative:9,perception:8,speed:"5",senses:["Darkvision"],powers:[{name:"Sickening Miasma",action:"Aura",description:"Aura 1 Whenever an enemy in the aura takes a standard action or a move action, it takes 2 damage"},{name:"Multiple",action:"Trait",description:"sickening miasma auras stack, dealing up to 10 damage"},{name:"Savage Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 12 damage."}],alignment:"Unaligned",languages:["Abyssal Monster Vault","page(s) 44","The Book of Vile Darkness","page(s) 2-87."] },
  { id:"mv-drow-stalker",name:"Drow Stalker",source:"mv",level:12,role:"Lurker",roleModifier:"Minion",xp:175,size:"Medium",origin:"Fey",type:"Humanoid",hp:1,ac:26,fort:22,ref:25,will:25,initiative:15,perception:7,speed:"6",senses:["Darkvision"],powers:[{name:"Stalker Ambush",action:"Trait",description:"When the drow hits a creature that cannot see it, the drow's attack deals 5 extra damage"},{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 10 damage."},{name:"Hand Crossbow",action:"Standard",keywords:["poison","weapon"],recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +17 vs. AC Hit: 5 damage, and ongoing 5 poison damage (save ends)."},{name:"Cloud of Darkness",action:"Minor",keywords:["zone"],recharge:"Encounter",description:"Effect: Close burst 1. The burst creates a zone that lasts until the end of the drow's next turn. The cloud blocks line of sight for all creatures except the drow. While entirely within the cloud, any creature other than the drow is blinded."}],alignment:"Unaligned",languages:["Common","Elven Monster Vault","page(s) 116."] },
  { id:"mv-earth-archon",name:"Earth Archon",source:"mv",level:12,role:"Brute",xp:700,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["earth"],hp:149,ac:25,fort:26,ref:23,will:21,initiative:5,perception:9,speed:"6 (earth walk)",senses:["Tremorsense 5"],immune:["disease, petrification, poison"],powers:[{name:"Earth Walk",action:"Trait",description:"The archon ignores difficult terrain that is rubble, uneven stone, or an earthen construction"},{name:"Shattering Tremors Whenever",action:"Trait",description:"the archon takes thunder damage, it is slowed until the end of its next turn"},{name:"Stony Warhammer",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 4d8 + 7 damage."},{name:"Avalanche Charge",action:"Standard",recharge:"Recharge when first bloodied",description:"Effect: Before the attack, the archon moves up to its speed. Attack: Melee 1 (one creature); +15 vs. Fortitude Hit: 4d12 + 9 damage, and the archon pushes the target up to 2 squares and knocks it prone. Miss: Half damage, and the target falls prone."}],alignment:"Unaligned",languages:["Primordial Monster Vault","page(s) 18."] },
  { id:"mv-flamekiss-hydra",name:"Flamekiss Hydra",source:"mv",level:12,role:"Brute",roleModifier:"Solo",xp:3500,size:"Large",origin:"Natural",type:"Beast",keywords:["reptile"],hp:496,ac:25,fort:26,ref:23,will:22,initiative:9,perception:15,speed:"5 All-around vision",senses:["Darkvision"],resist:["10 fire"],powers:[{name:"All-Around Vision",action:"Trait",description:"Enemies can't gain combat advantage by flanking the hydra"},{name:"Many Headed",action:"Trait",description:"While stunned or dominated, the hydra can take free actions"},{name:"Regenerating Heads",action:"Trait",description:"The hydra starts an encounter with four heads"},{name:"When",action:"Trait",description:"the hydra's hit points first go below 372, 248, and 124, one of its heads is destroyed"},{name:"Whenever",action:"Trait",description:"a head is destroyed, the hydra grows two heads at the start of its next turn unless it takes cold or acid damage before then"},{name:"Threatening Reach",action:"Trait",description:"The hydra can make opportunity attacks against enemies within 2 squares of it"},{name:"Bite",action:"Standard",description:"Attack: Melee 2 (one creature); +17 vs. AC Hit: 3d12 damage."},{name:"Flame Kiss",action:"Standard",keywords:["fire"],recharge:"Recharge when the hydra loses a head",description:"Attack: Close blast 3 (creatures in the blast); +13 vs. Reflex Hit: 2d8 + 5 fire damage, and ongoing 10 fire damage (save ends). The hydra pushes the target up to 3 squares. Hydra Fury ✦ At-Will Effect: The hydra attacks a number of times equal to the number of heads it currently has, using either bite or flame kiss for each attack. If it has only two heads, it gains a +5 bonus to damage rolls with the attacks. If it has only one head, it gains a +15 bonus to damage rolls with the attack."},{name:"Snapping Jaws",action:"Triggered",description:"Trigger: An enemy ends its turn within 2 squares of the hydra. Effect (Free Action): The hydra uses bite twice against the triggering enemy."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 176","Dungeon Magazine 196."] },
  { id:"mv-green-hag",name:"Green Hag",source:"mv",level:12,role:"Controller",xp:700,size:"Medium",origin:"Fey",type:"Humanoid",keywords:["shapechanger"],hp:124,ac:26,fort:25,ref:24,will:23,initiative:10,perception:14,speed:"8 (forest walk, swamp walk), swim 8",senses:["Low-light vision"],resist:["10 poison"],powers:[{name:"Hurl through the Earth",action:"Standard",keywords:["teleportation"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d6 + 9 damage. Effect: The hag teleports the target up to 3 squares."},{name:"Grasping Roots",action:"Standard",description:"Attack: Area burst 2 within 5 (creatures in the burst); +15 vs. Reflex Hit: The target is restrained (save ends). Miss: The target is slowed until the end of the hag's next turn."},{name:"Rampant Growth",action:"Standard",keywords:["zone"],recharge:"Encounter",description:"Attack: Area burst 2 within 5 centered on a creature restrained by grasping roots (creatures in the burst); +15 vs. Reflex Hit: 2d8 + 8 damage. Effect: The burst creates a zone that lasts until the end of the encounter. Squares in the zone are difficult terrain for any creature that doesn't have forest walk, and such a creature takes 5 damage for each square of movement in the zone."},{name:"Stagnant Miasma",action:"Standard",keywords:["poison","zone"],recharge:"Recharge 4-6",description:"Attack: Area burst 2 within 5 (creatures in the burst); +15 vs. Fortitude Hit: 2d10 + 11 poison damage. Effect: The burst creates a zone of lightly obscured squares that lasts until the end of the hag's next turn. Any creature that ends its turn in the zone takes 10 poison damage."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The hag alters its physical form to appear as a crone or a young woman of any Medium humanoid race until it uses change shape again or until it drops to 0 hit points. To assume a specific individual's form, the hag must have seen that individual. Other creatures can make a DC 33 Insight check to discern that the form is a disguise. Skills Bluff +14, Stealth +15"}],alignment:"Unaligned",languages:["Common","Elven Monster Vault","page(s) 166","Dungeon Magazine 196."] },
  { id:"mv-master-vampire",name:"Master Vampire",source:"mv",level:12,role:"Lurker",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:98,ac:26,fort:25,ref:24,will:24,initiative:15,perception:14,speed:"7, climb 4 (spider climb)",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],powers:[{name:"Burned",action:"Trait",description:"by Sunlight (radiant) Whenever the vampire starts its turn in direct sunlight, it takes 10 radiant damage"},{name:"Regeneration",action:"Trait",description:"The vampire regains 10 hit points whenever it starts its turn and has at least 1 hit point"},{name:"When",action:"Trait",description:"the vampire takes radiant damage, its regeneration does not function on its next turn"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 3d6 + 5 damage."},{name:"Bite",action:"Standard",keywords:["healing"],description:"Attack: Melee 1 (one dazed, dominated, stunned, or unconscious creature); +17 vs. AC Hit: 4d10 + 10 damage, and the vampire regains 20 hit points. Cloud of Bats (polymorph) ✦ At-Will Effect: The vampire assumes the form of a cloud of bats until the start of its next turn. While in this form, the vampire cannot attack but becomes insubstantial, gains fly 8 (hover), gains a +5 power bonus to Stealth checks, and can move through enemies' spaces."},{name:"Dominating Gaze",action:"Standard",keywords:["charm"],recharge:"Recharge when no creature is dominated by this power",description:"Attack: Ranged 5 (one creature); +17 vs. Will Hit: The target is dominated until the end of the vampire's next turn."},{name:"Mist Form",action:"Triggered",keywords:["polymorph"],recharge:"Encounter",description:"Trigger: The vampire takes damage while bloodied. Effect (No Action): The vampire becomes insubstantial and gains fly 12. The vampire cannot attack or use cloud of bats. This effect lasts for 1 hour or until the vampire ends it as a minor action. Skills Acrobatics +16, Athletics +17, Bluff +16, Insight +14, Stealth +16"}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 283."] },
  { id:"mv-medusa-bodyguard",name:"Medusa Bodyguard",source:"mv",level:12,role:"Soldier",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",hp:123,ac:28,fort:25,ref:23,will:24,initiative:11,perception:15,speed:"6",resist:["10 poison"],powers:[{name:"Bastard Sword",action:"Standard",keywords:["poison","weapon"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d10 + 4 damage, and ongoing 5 poison damage (save ends). Effect: The bodyguard marks the target until the end of the bodyguard's next turn."},{name:"Longbow",action:"Standard",keywords:["poison","weapon"],description:"Attack: Ranged 30 (one creature); +17 vs. AC Hit: 1d10 + 9 damage, and ongoing 5 poison damage (save ends)."},{name:"Mind-Venom Gaze",action:"Triggered",keywords:["charm","poison","psychic"],recharge:"Recharge when the bodyguard hits with bastard sword",description:"Trigger: An enemy marked by the bodyguard makes an attack that does not include it as a target. Attack (Immediate Interrupt): Close blast 5 (enemies in the blast); +15 vs. Will. The attack must include the triggering enemy as a target. Hit: 2d6 + 3 poison and psychic damage, and if the target is the triggering enemy, the target is stunned until the end of its turn. Skills Bluff +14, Stealth +14"}],alignment:"Unaligned",languages:["Common Equipment : bastard sword","longbow . Monster Vault","page(s) 201","Dungeon Magazine 196","Dungeon Magazine 218."] },
  { id:"mv-medusa-venom-arrow",name:"Medusa Venom Arrow",source:"mv",level:12,role:"Artillery",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",hp:96,ac:26,fort:23,ref:25,will:23,initiative:12,perception:14,speed:"6",resist:["10 poison"],immune:["petrification"],powers:[{name:"Serpent Hair",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d6 + 6 poison damage, and the target takes a -2 penalty to saving throws until the end of the medusa's next turn."},{name:"Shortbow",action:"Standard",keywords:["poison","weapon"],description:"Attack: Ranged 30 (one creature); +19 vs. AC Hit: 1d10 + 7 damage, and the target takes ongoing 5 poison damage and is slowed (save ends both)."},{name:"Petrifying Stare",action:"Triggered",description:"Trigger: An enemy starts its turn within 2 squares of the medusa. Effect (Opportunity Action): Close blast 2 (the triggering enemy in the blast). The target is slowed (save ends). First Failed Saving Throw: The target is immobilized instead of slowed (save ends). Second Failed Saving Throw: The target is petrified until one of the following conditions is satisfied. ✦ The use of an appropriate power, such as divine cleansing. ✦ The willing kiss of the medusa that petrified the creature (a medusa might do this to gain information or to luxuriate in the victim's fear before returning it to stone). ✦ The medusa responsible for the petrification is killed and its blood is applied to the stony lips of the victim before a full day passes. Skills Bluff +15, Stealth +17"}],alignment:"Unaligned",languages:["Common Equipment : shortbow . Monster Vault","page(s) 202","Dungeon Magazine 196","Dungeon Magazine 218."] },
  { id:"mv-royal-mummy",name:"Royal Mummy",source:"mv",level:12,role:"Controller",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:236,ac:26,fort:24,ref:22,will:26,initiative:5,perception:9,speed:"4",senses:["Darkvision"],resist:["10 necrotic,","10 poison"],immune:["disease"],powers:[{name:"Regal Presence",action:"Aura",description:"Aura 5 Whenever an ally starts its turn in the aura, the mummy slides that ally up to 2 squares as a free action."},{name:"Curse of Fear",action:"Aura",keywords:["fear"],description:"Aura 5 Enemies take a -2 penalty to all defenses against the mummy's attacks while in the aura"},{name:"Flammable Corpus Whenever",action:"Trait",description:"the mummy takes fire damage, it also takes ongoing 5 fire damage (save ends)"},{name:"Scepter",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d8 + 9 damage."},{name:"Plague Chant",action:"Standard",keywords:["necrotic"],description:"Attack: Ranged 10 (one creature); +15 vs. Fortitude Hit: 2d6 + 6 necrotic damage, and ongoing 5 necrotic damage (save ends). Each time the target takes this ongoing damage, each ally adjacent to it takes 5 necrotic damage."},{name:"Grip of Despair",action:"Standard",keywords:["fear","psychic"],description:"Attack: Ranged 10 (one creature); +15 vs. Will Hit: 1d12 + 9 psychic damage, and the target is immobilized and takes a -2 penalty to attack rolls until the end of the mummy's next turn."},{name:"Sow Fear and Pestilence",action:"Standard",description:"Effect: The mummy uses plague chant and grip of despair."},{name:"Grave Terror",action:"Standard",keywords:["fear","psychic"],recharge:"Encounter",description:"Attack: Close burst 3 (enemies in the burst); +15 vs. Will Hit: 2d10 + 13 psychic damage, and the mummy pushes the target up to 4 squares. Miss: Half damage, and the mummy pushes the target up to 2 squares."},{name:"Enfeebling Curse",action:"Minor",description:"1/round Effect: Ranged 10 (one creature). Whenever the target spends a healing surge, it becomes weakened until the end of its next turn. This effect lasts until the mummy uses this power again or until the target takes an extended rest. Skills Insight +14, Religion +13"}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 214."] },
  { id:"mv-snake-swarm",name:"Snake Swarm",source:"mv",level:12,role:"Brute",xp:700,size:"Medium",origin:"Natural",type:"Beast",keywords:["reptile","swarm"],hp:149,ac:24,fort:25,ref:24,will:23,initiative:10,perception:9,speed:"6, climb 6",senses:["Low-light vision"],resist:["half damage from melee and ranged attacks"],vulnerable:["10 to close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",keywords:["poison"],description:"Aura 1 An enemy that ends its turn in the aura takes 10 poison damage"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for at least one of the creatures it comprises"},{name:"Swarm of Fangs",action:"Standard",keywords:["poison"],description:"Attack: Close burst 1 (enemies in the burst); +17 vs. AC Hit: 2d8 + 8 poison damage, and the target is slowed (save ends). Skills Stealth +15"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 301."] },
  { id:"mv-abyssal-basilisk",name:"Abyssal Basilisk",source:"mv",level:13,role:"Artillery",xp:800,size:"Large",origin:"Elemental",type:"Beast",keywords:["reptile"],hp:106,ac:27,fort:26,ref:23,will:23,initiative:7,perception:13,speed:"4",powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d10 + 5 damage."},{name:"Gaze of Abyssal Horror",action:"Standard",keywords:["charm","psychic"],description:"Attack: Area burst 1 within 10 (creatures in the burst); +18 vs. Will Hit: 2d8 + 2 psychic damage, and ongoing 10 psychic damage (save ends). First Failed Saving Throw: The target makes a melee basic attack or a ranged basic attack against its nearest ally as a free action. Second Failed Saving Throw: The target takes ongoing 10 psychic damage and is dominated (save ends both). Skills Stealth +12"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 23","Dungeon Magazine 196."] },
  { id:"mv-displacer-beast-pack-lord",name:"Displacer Beast Pack Lord",source:"mv",level:13,role:"Skirmisher",roleModifier:"Elite",xp:1600,size:"Huge",origin:"Fey",type:"Magical beast",hp:258,ac:27,fort:25,ref:26,will:24,initiative:14,perception:15,speed:"12",senses:["Low-light vision"],powers:[{name:"Displacement",action:"Trait",keywords:["illusion"],description:"When a melee or a ranged attack hits the pack lord, if the player rolled an odd number on the attack roll, the attack misses"},{name:"If",action:"Trait",description:"the player rolled an even number on the attack roll, the attack hits as normal, and the beast loses this trait until the start of its next turn"},{name:"Nimble Stride",action:"Trait",description:"The pack lord ignores difficult terrain and speed penalties for squeezing"},{name:"Threatening Reach",action:"Trait",description:"The pack lord can make opportunity attacks against enemies within 3 squares of it"},{name:"Tentacle",action:"Standard",description:"Attack: Melee 3 (one creature); +18 vs. AC Hit: 3d8 + 7 damage."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d12 + 10 damage."},{name:"Cunning Blitz",action:"Standard",description:"Effect: The pack lord shifts up to half its speed. At any point during that movement, it uses tentacle once, or two times against different creatures."},{name:"Clear the Path",action:"Standard",recharge:"Recharge when first bloodied",description:"Attack: Close burst 3 (enemies in the burst); +16 vs. Reflex Hit: 2d6 + 7 damage, and the pack lord slides the target up to 3 squares. Miss: Half damage, and the pack lord can slide the target 1 square."},{name:"Superior Shifting Tactics",action:"Triggered",description:"Trigger: An attack misses the pack lord. Effect (Free Action): The pack lord shifts 1 square. Before or after the movement, it uses tentacle. Skills Stealth +17"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 59."] },
  { id:"mv-fire-archon",name:"Fire Archon",source:"mv",level:13,role:"Skirmisher",xp:800,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["fire"],hp:130,ac:27,fort:25,ref:26,will:23,initiative:14,perception:9,speed:"8",resist:["20 fire"],immune:["disease, poison"],powers:[{name:"Guttering Flames Whenever",action:"Trait",description:"the archon takes cold damage, it cannot shift until the end of its next turn"},{name:"Fiery Scimitar",action:"Standard",keywords:["fire"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 3d8 + 8 fire damage."},{name:"Flickering Step",action:"Move",description:"Effect: The archon shifts up to half its speed. Blaze Step (fire) ✦ Encounter Effect: The archon shifts up to its speed. Each square it shifts through fills with elemental flames that last until the end of the encounter. Each time a nonfire creature enters or starts its turn in a square filled with these flames, it takes 10 fire damage."}],alignment:"Unaligned",languages:["Primordial Monster Vault","page(s) 18","Dungeon Magazine 196."] },
  { id:"mv-githyanki-legionary",name:"Githyanki Legionary",source:"mv",level:13,role:"Soldier",roleModifier:"Minion",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:29,fort:26,ref:23,will:25,initiative:10,perception:9,speed:"5",powers:[{name:"Silver Short Sword",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 10 damage, plus 5 psychic damage if the target is immobilized."},{name:"Telekinetic Grasp",action:"Standard",recharge:"Encounter",description:"Attack: Ranged 5 (one creature); +16 vs. Fortitude Hit: The target is immobilized (save ends)."}],alignment:"Unaligned",languages:["Common","Deep Speech Equipment : silver short sword","chainmail . Monster Vault","page(s) 141."] },
  { id:"mv-githyanki-raider",name:"Githyanki Raider",source:"mv",level:13,role:"Skirmisher",xp:800,size:"Medium",origin:"Natural",type:"Humanoid",hp:126,ac:27,fort:23,ref:25,will:27,initiative:11,perception:9,speed:"6",powers:[{name:"Combat Advantage",action:"Trait",keywords:["psychic"],description:"The githyanki deals 2d8 extra psychic damage against any creature granting combat advantage to it"},{name:"Silver Longsword",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d8 + 12 psychic damage."},{name:"Raider's Strike",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d8 + 12 psychic damage. Effect: The githyanki shifts up to 2 squares."},{name:"Slash and Dash",action:"Standard",keywords:["psychic","weapon"],recharge:"Encounter",description:"Attack: Melee 1 (one or two creatures); +18 vs. AC. The githyanki can shift up to its speed before making the second attack Hit: 4d8 + 14 psychic damage. Miss: Half damage."},{name:"Raider's Step",action:"Move",description:"Effect: The githyanki shifts up to 2 squares."},{name:"Telekinetic Leap",action:"Move",recharge:"Encounter",description:"Effect: The githyanki flies up to 5 squares, or one ally within 10 squares of it can fly up to 5 squares as a free action. Skills History +10, Insight +14"}],alignment:"Unaligned",languages:["Common","Deep Speech Equipment : silver longsword","leather armor . Monster Vault","page(s) 140","Dungeon Magazine 203."] },
  { id:"mv-hill-giant-earth-shaman",name:"Hill Giant Earth Shaman",source:"mv",level:13,role:"Controller",xp:800,size:"Large",origin:"Natural",type:"Humanoid",keywords:["earth","giant"],hp:131,ac:27,fort:25,ref:23,will:23,initiative:6,perception:8,speed:"8",powers:[{name:"Earthgrip Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +18 vs. AC Hit: 2d8 + 10 damage, and the target is restrained until the end of the giant's next turn."},{name:"Earthen Chains",action:"Standard",keywords:["healing"],recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +16 vs. Reflex Hit: 1d8 + 5 damage, and the target is stunned (save ends). If the target is flying, it falls. The first time one of the giant's allies hits the target while it is stunned by this power, that ally regains 15 hit points."},{name:"Earth Wave",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +16 vs. Fortitude Hit: 1d10 + 4 damage, and the giant pushes the target up to 2 squares. Effect: The target falls prone. Each ally in the blast can use a free action to shift up to 3 squares and make a basic attack."}],alignment:"Unaligned",languages:["Giant Monster Vault","page(s) 133."] },
  { id:"mv-hill-giant-hunter",name:"Hill Giant Hunter",source:"mv",level:13,role:"Artillery",xp:800,size:"Large",origin:"Natural",type:"Humanoid",keywords:["earth","giant"],hp:103,ac:27,fort:26,ref:23,will:23,initiative:5,perception:12,speed:"8",powers:[{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +18 vs. AC Hit: 2d8 + 12 damage."},{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +20 vs. AC Hit: 2d8 + 12 damage."},{name:"Hurl Rock",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Ranged 20 (one creature); +20 vs. AC Hit: 3d8 + 20 damage, the giant can push the target 1 square, and the target falls prone."}],alignment:"Unaligned",languages:["Giant Equipment : rock x4","javelin x6. Monster Vault","page(s) 132","Dungeon Magazine 197."] },
  { id:"mv-ice-archon",name:"Ice Archon",source:"mv",level:13,role:"Soldier",xp:800,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["cold"],hp:135,ac:29,fort:27,ref:25,will:22,initiative:8,perception:9,speed:"6",resist:["20 cold"],immune:["disease, poison"],powers:[{name:"Chilling Aura",action:"Aura",description:"Aura 2 Enemies cannot shift while in the aura"},{name:"Melting Ice Whenever",action:"Trait",description:"the archon takes fire damage, it takes a -2 penalty to all defenses until the end of its next turn"},{name:"Frigid Mace",action:"Standard",keywords:["cold"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 4d6 + 7 cold damage. Effect: The archon marks each enemy within 2 squares of it until the end of the archon's next turn."},{name:"Frozen Rebuke",action:"Triggered",description:"Trigger: An enemy marked by the archon makes an attack that doesn't include it as a target. Attack (Immediate Reaction): Melee 1 (the triggering enemy); +18 vs. AC Hit: 2d8 + 5 damage, and the target is weakened until the end of its next turn."}],alignment:"Unaligned",languages:["Primordial Monster Vault","page(s) 19."] },
  { id:"mv-manticore-sky-hunter",name:"Manticore Sky Hunter",source:"mv",level:13,role:"Soldier",xp:0,size:"Large",origin:"Natural",type:"Magical beast",hp:130,ac:29,fort:26,ref:26,will:23,initiative:14,perception:14,speed:"6, fly 8",powers:[{name:"Shielding Wings",action:"Aura",description:"Aura 1 Allies gain a +2 bonus to AC and Reflex while in the aura."},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d10 + 10 damage, or 2d10 + 12 if the target is marked by the manticore."},{name:"Tail Spike",action:"Standard",description:"Attack: Ranged 10 (one creature); +18 vs. AC Hit: 2d8 + 6 damage."},{name:"Threatening Roar",action:"Minor",keywords:["charm"],description:"Effect: Close burst 1 (enemies in the burst). The manticore marks each target until the end of the manticore's next turn"},{name:"Defender's Spike",action:"Triggered",description:"Trigger: An enemy within 5 squares of the manticore and marked by the manticore makes an attack that doesn't include it as a target. Effect (Immediate Reaction): The manticore uses tail spike against the triggering enemy. This attack does not provoke opportunity attacks."}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 199","Dungeon Magazine 209."] },
  { id:"mv-manticore-spike-hurler",name:"Manticore Spike Hurler",source:"mv",level:13,role:"Artillery",xp:800,size:"Large",origin:"Natural",type:"Magical beast",hp:100,ac:27,fort:25,ref:26,will:23,initiative:12,perception:14,speed:"6, fly 8",powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 3d6 + 9 damage."},{name:"Tail Spike",action:"Standard",description:"Attack: Ranged 10 (one creature); +20 vs. AC Hit: 2d8 + 12 damage."},{name:"Spike Volley",action:"Standard",description:"Attack: Area burst 1 within 10 (creatures in the burst); +20 vs. AC Hit: 2d8 + 9 damage."}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 199","Dungeon Magazine 209."] },
  { id:"mv-medusa-spirit-charmer",name:"Medusa Spirit Charmer",source:"mv",level:13,role:"Controller",xp:800,size:"Medium",origin:"Natural",type:"Humanoid",hp:130,ac:27,fort:25,ref:25,will:27,initiative:9,perception:14,speed:"6",resist:["10 poison"],immune:["petrification"],powers:[{name:"Serpent Hair",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d6 + 6 poison damage, and the target takes a -2 penalty to saving throws until the end of the medusa's next turn."},{name:"Spirit Charm",action:"Standard",keywords:["charm","psychic"],description:"Attack: Close blast 5 (enemies in the blast); +16 vs. Will Hit: 1d6 + 6 psychic damage, and the target must end its next turn 2 squares closer to or adjacent to the medusa or else take 3d6 psychic damage."},{name:"Swords to Snakes",action:"Standard",keywords:["fear","illusion"],recharge:"Encounter",description:"Attack: Area burst 1 within 10 (enemies in the burst); +16 vs. Will Hit: The target's weapons and implements appear to become snakes, and the target cannot use weapon or implement powers (save ends)."},{name:"Stony Glare",action:"Triggered",description:"Trigger: An enemy ends its turn within 2 squares of the medusa. Attack (Immediate Reaction): Close burst 2 (the triggering enemy in the blast); +16 vs. Fortitude Hit: The target is petrified (save ends). Third Failed Saving Throw: The target is petrified until one of the following conditions is satisfied. ✦ : The use of an appropriate power, such as divine cleansing. ✦ : The willing kiss of the medusa that petrified the creature (a medusa might do this to gain information or to luxuriate in the victim's fear before returning it to stone). ✦ : The medusa responsible for the petrification is killed and its blood is applied to the stony lips of the victim before a full day passes. Skills Bluff +17, Stealth +14"}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 203","Dungeon Magazine 198."] },
  { id:"mv-yuan-ti-malison-stalker",name:"Yuan-ti Malison Stalker",source:"mv",level:13,role:"Skirmisher",xp:800,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:126,ac:27,fort:24,ref:27,will:25,initiative:14,perception:13,speed:"7",resist:["10 poison"],powers:[{name:"Morningstar",action:"Standard",keywords:["poison","weapon"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d8 + 7 damage, and the target cannot mark enemies and takes ongoing 5 poison damage (save ends both)."},{name:"Poisoned Dagger",action:"Standard",keywords:["poison","weapon"],description:"Attack: Ranged 10 (one creature); +18 vs. AC Hit: 3d4 + 6 damage, and ongoing 5 poison damage (save ends)."},{name:"Slither Strike",action:"Standard",description:"Effect: The yuan-ti ends any marking effect on it and then shifts up to 4 squares. At any point during the shift, the yuan-ti can use morningstar or poisoned dagger. Skills Bluff +15, Insight +13, Stealth +17"}],alignment:"Unaligned",languages:["Common","Draconic Equipment : dagger x5","morningstar . Monster Vault","page(s) 289."] },
  { id:"mv-adult-purple-worm",name:"Adult Purple Worm",source:"mv",level:14,role:"Brute",roleModifier:"Solo",xp:5000,size:"Huge",origin:"Natural",type:"Beast",keywords:["blind"],hp:560,ac:28,fort:28,ref:26,will:24,initiative:12,perception:11,speed:"6, burrow 6 (tunneling)",senses:["Blindsight 10"],immune:["blinded, gaze effects"],powers:[{name:"Ponderous",action:"Trait",description:"The purple worm can take immediate actions while stunned, dazed, or dominated"},{name:"Blooded Frenzy",action:"Trait",description:"While bloodied, the purple worm takes an extra minor action during its turn"},{name:"Bite",action:"Standard",description:"Attack: Melee 3 (one creature); +19 vs. AC Hit: 4d8 + 8 damage."},{name:"Devour Whole",action:"Standard",keywords:["acid"],description:"Attack: Melee 3 (one creature); +17 vs. Fortitude Hit: 3d10 + 7 damage, and the target is swallowed (escape DC 21). While swallowed, the target does not occupy a square and has neither line of sight nor line of effect to anything except the worm and other creatures swallowed by the worm; in addition, nothing has line of sight or line of effect to the target except other creatures swallowed by the worm. If the target attacks the worm using a close or an area attack, that attack targets all other creatures swallowed by the worm. While swallowed, the target takes 30 acid damage at the end of its turn. When the effect ends or the worm drops to 0 hit points, the target appears in an unoccupied square of its choice adjacent to the worm."},{name:"Fling",action:"Minor",description:"Attack: Melee 3 (one creature); +17 vs. Fortitude Hit: 3d10 + 8 damage, and the purple worm slides the target up to 4 squares."},{name:"Poison Stinger",action:"Minor",keywords:["poison"],description:"Attack: Melee 3 (one creature); +19 vs. AC Hit: 2d8 damage, and ongoing 15 poison damage (save ends). Regurgitate ✦ At-Will Effect: One creature swallowed by the purple worm appears in a square of the worm's choice within 4 squares of it. That creature is no longer swallowed and takes 3d10 + 8 damage."},{name:"Thrash",action:"Triggered",description:"Trigger: An attack hits the purple worm. Attack (Immediate Reaction): Melee 3 (one or two creatures); +17 vs. Reflex Hit: 3d12 + 5 damage, and the purple worm pushes the target up to 6 squares."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 240."] },
  { id:"mv-drider",name:"Drider",source:"mv",level:14,role:"Soldier",xp:1000,size:"Large",origin:"Natural",type:"Humanoid",hp:138,ac:30,fort:27,ref:25,will:26,initiative:13,perception:7,speed:"8, climb 8 (spider climb)",senses:["Darkvision"],powers:[{name:"Threatening Reach",action:"Trait",description:"The drider can make opportunity attacks against all enemies within 2 squares of it"},{name:"Scimitar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +19 vs. AC Hit: 3d8 + 9 damage. Effect: The drider marks the target until the end of the drider's next turn."},{name:"Darkfire",action:"Minor",recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +17 vs. Reflex Hit: The target grants combat advantage and cannot benefit from invisibility or concealment until the end of the drider's next turn."},{name:"Servant's Rebuke",action:"Triggered",keywords:["necrotic","poison"],description:"Trigger: An enemy marked by the drider shifts or makes an attack that doesn't include it as a target. Effect (Opportunity Action): Close burst 10 (the triggering enemy in the burst). The target takes 15 necrotic and poison damage. Skills Stealth +16"}],alignment:"Unaligned",languages:["Elven Equipment : leather armor","scimitar . Monster Vault","page(s) 87."] },
  { id:"mv-lich-necromancer",name:"Lich Necromancer",source:"mv",level:14,role:"Controller",roleModifier:"Elite",xp:2000,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:268,ac:28,fort:24,ref:28,will:27,initiative:8,perception:9,speed:"6",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],powers:[{name:"Necromantic Aura",action:"Aura",keywords:["necrotic"],description:"Aura 5 Any living creature that ends its turn in the aura takes 5 necrotic damage"},{name:"Whenever",action:"Trait",description:"the lich takes radiant damage, its aura is deactivated until the end of the lich's next turn"},{name:"Soul Phylactery",action:"Trait",description:"When the lich drops to 0 hit points, its body and possessions crumble into dust and it disappears, but it is not destroyed"},{name:"It",action:"Trait",description:"reappears (along with its possessions) in 1d10 days within 1 square of its phylactery, unless the phylactery is destroyed"},{name:"Vampiric Touch",action:"Standard",keywords:["healing","necrotic"],description:"Attack: Melee 1 (one creature); +17 vs. Fortitude Hit: 2d8 + 7 necrotic damage, and the lich regains hit points equal to the damage dealt."},{name:"Freezing Claw",action:"Standard",keywords:["cold","necrotic"],description:"Attack: Ranged 5 (one or two creatures); +17 vs. Reflex Hit: 2d8 + 10 cold and necrotic damage, and the target is immobilized (save ends). Miss: The target is slowed (save ends)."},{name:"Enervating Tendrils",action:"Standard",keywords:["necrotic"],recharge:"Recharge when first bloodied",description:"Attack: Area burst 1 within 10 (enemies in the burst); +17 vs. Fortitude Hit: 6d6 + 7 necrotic damage, and the target is weakened (save ends). Miss: Half damage."},{name:"Shadow Walk",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: The lich teleports up to twice its speed."},{name:"Lich's Control",action:"Minor",recharge:"Recharge 4-6",description:"Effect: Close burst 10 (one enemy in the burst that is subject to an effect a save can end). The target takes a -5 penalty to its next saving throw. Skills Arcana +18, History +18, Insight +14"}],alignment:"Unaligned",languages:["Abyssal","Common Monster Vault","page(s) 183."] },
  { id:"mv-mind-flayer-thrall-master",name:"Mind Flayer Thrall Master",source:"mv",level:14,role:"Controller",roleModifier:"Elite",xp:0,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:260,ac:28,fort:23,ref:27,will:26,initiative:9,perception:10,speed:"7",senses:["Darkvision"],powers:[{name:"Tentacles",action:"Standard",description:"Requirement: The mind flayer must not have a creature grabbed. Attack: Melee 1 (one creature); +17 vs. Reflex. This attack automatically hits a dazed or stunned target. Hit: 3d6 + 5 damage, and the mind flayer grabs the target (escape DC 21) if it does not have a creature grabbed."},{name:"Manipulate Brain",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the mind flayer); +17 vs. Fortitude Hit: 4d6 + 10 damage, and the target is stunned until it is no longer grabbed by the mind flayer. If this attack reduces the target to 0 hit points or fewer, the mind flayer does one of the following. Eat Brain (healing): The target dies, and the mind flayer regains 20 hit points. Thrall Surgery (charm): Instead of dropping to 0 hit points or fewer, the target remains at 1 hit point. It is dominated until the mind flayer dies."},{name:"Mind Blast",action:"Standard",keywords:["psychic"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +17 vs. Will Hit: 3d8 + 10 psychic damage, and the target is dazed (save ends). If the mind flayer scores a critical hit against the target, the target is dominated instead of dazed (save ends). Miss: Half damage."},{name:"Thrall Strike",action:"Minor",keywords:["charm"],description:"1/round Effect: Ranged sight (one ally or creature dominated by the mind flayer). The target makes a basic attack as a free action."},{name:"Teleport Thrall",action:"Triggered",keywords:["teleportation"],description:"Trigger: An enemy targets the mind flayer with a melee attack. Effect (Immediate Interrupt): Close burst 5 (one ally or creature in the burst dominated by the mind flayer). The mind flayer teleports up to 5 squares and teleports the target to the square it vacated. The triggering attack targets the target instead of the mind flayer. Skills Arcana +18, Insight +15"}],alignment:"Unaligned",languages:["Deep Speech","telepathy 20 Monster Vault","page(s) 205","Dungeon Magazine 201."] },
  { id:"mv-water-archon",name:"Water Archon",source:"mv",level:14,role:"Controller",xp:1000,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["aquatic","water"],hp:140,ac:28,fort:26,ref:24,will:28,initiative:11,perception:8,speed:"6, swim 6",resist:["20 acid"],immune:["disease, poison"],powers:[{name:"Aquatic",action:"Trait",description:"The archon can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Frozen Waves Whenever",action:"Trait",description:"the archon takes cold damage, it is slowed until the end of its next turn"},{name:"Cresting Staff",action:"Standard",description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 2d10 + 10 damage, and the target is slowed until the end of the archon's next turn."},{name:"Whirlpool",action:"Standard",description:"Attack: Close burst 3 (enemies in the burst); +17 vs. Fortitude Hit: 4d6 + 7 damage, and the archon slides the target up to 3 squares. Miss: The archon can slide the target 1 square."}],alignment:"Unaligned",languages:["Primordial Monster Vault","page(s) 19."] },
  { id:"mv-bough-dryad",name:"Bough Dryad",source:"mv",level:15,role:"Skirmisher",roleModifier:"Minion",xp:300,size:"Medium",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:1,ac:29,fort:28,ref:28,will:26,initiative:16,perception:17,speed:"8 (forest walk)",powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 11 damage, or 13 if no other enemy is adjacent to the dryad."},{name:"Boon of Life",action:"Triggered",recharge:"Encounter",description:"Trigger: The dryad drops to 0 hit points. Effect (No Action): Close burst 5 (one ally in the burst). The target gains 5 temporary hit points."}],alignment:"Unaligned",languages:["Elven Monster Vault","page(s) 93","Dungeon Magazine 185","Dungeon Magazine 189."] },
  { id:"mv-carrion-crawler-putrefier",name:"Carrion Crawler Putrefier",source:"mv",level:15,role:"Soldier",xp:1200,size:"Large",origin:"Aberrant",type:"Beast",hp:148,ac:31,fort:28,ref:26,will:25,initiative:13,perception:9,speed:"6, climb 6 (spider climb)",senses:["Darkvision"],powers:[{name:"Nauseous Stench",action:"Aura",keywords:["poison"],description:"Aura 3 Any enemy that starts its turn in the aura takes 5 poison damage and is slowed (save ends both)."},{name:"Rotting Tentacles",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 3 (one creature); +18 vs. Fortitude Hit: 2d10 + 6 necrotic damage, the carrion crawler can pull the target 1 square, and the target is immobilized (save ends). If the target was already immobilized, it is instead stunned and takes ongoing 10 necrotic damage (save ends both)."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 2d12 + 10 damage."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 33."] },
  { id:"mv-crag-roper",name:"Crag Roper",source:"mv",level:15,role:"Soldier",roleModifier:"Elite",xp:2400,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["earth"],hp:304,ac:31,fort:29,ref:24,will:26,initiative:10,perception:11,speed:"2, climb 2 (spider climb)",senses:["Darkvision"],powers:[{name:"Lashing Tentacles",action:"Aura",description:"Aura 5 Any enemy that enters the aura or starts its turn there is marked by the roper until it is no longer in the aura"},{name:"Enemies",action:"Trait",description:"marked by the roper cannot be marked by other creatures while the enemies are in the aura"},{name:"Stony Body",action:"Trait",description:"The roper can retract its tentacles and close its eye and mouth to resemble a natural rock formation"},{name:"While",action:"Trait",description:"the roper is on a horizontal rock surface, a creature must succeed on a DC 30 Perception check to see through the roper's disguise"},{name:"Tentacle",action:"Standard",description:"Attack: Melee 10 (one creature); +18 vs. Reflex Hit: 3d8 + 11 damage, and the roper grabs the target (escape DC 22)."},{name:"Double Attack",action:"Standard",description:"Effect: The roper uses tentacle twice."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the roper); +20 vs. AC Hit: 4d12 + 18 damage. Miss: Half damage."},{name:"Reel",action:"Minor",description:"1/round Attack: Melee 10 (each creature grabbed by the roper); +20 vs. Fortitude Hit: The roper pulls the target up to 5 squares."},{name:"Tentacle Retaliation",action:"Triggered",description:"Trigger: An enemy marked by the roper makes an attack that doesn't include it as a target. Effect (Immediate Reaction): The roper uses tentacle against the triggering enemy. Skills Stealth +13"}],alignment:"Unaligned",languages:["Primordial Monster Vault","page(s) 249","Dungeon Magazine 198."] },
  { id:"mv-umber-hulk-bewilderer",name:"Umber Hulk Bewilderer",source:"mv",level:15,role:"Controller",xp:1200,size:"Large",origin:"Natural",type:"Magical beast",hp:148,ac:29,fort:28,ref:26,will:25,initiative:11,perception:15,speed:"5, burrow 2 (tunneling)",senses:["Darkvision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +20 vs. AC Hit: 1d8 + 6 damage, or 2d8 + 12 against a stunned or dazed target."},{name:"Stunning Gaze",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +18 vs. Will Hit: The target is stunned until the end of the umber hulk's next turn."},{name:"Staggering Gaze",action:"Minor",keywords:["psychic"],description:"1/round Attack: Close blast 5 (enemies in the blast); +18 vs. Will Hit: 1d10 + 5 psychic damage, and the umber hulk slides the target up to 5 squares."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 278","Dungeon Magazine 197."] },
  { id:"mv-umber-hulk-tunneler",name:"Umber Hulk Tunneler",source:"mv",level:15,role:"Skirmisher",xp:1200,size:"Large",origin:"Natural",type:"Magical beast",hp:148,ac:29,fort:28,ref:26,will:25,initiative:13,perception:15,speed:"5, burrow 2 (tunneling)",senses:["Darkvision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +20 vs. AC Hit: 1d8 + 7 damage."},{name:"Snatch and Run",action:"Standard",description:"Effect: The umber hulk uses claw twice against the same target. If at least one of the attacks hits, the umber hulk shifts up to 5 squares, pulling the target with it to a square adjacent to it."},{name:"Rebuffing Gaze",action:"Minor",keywords:["psychic"],description:"1/round Attack: Close blast 5 (enemies in the blast); +18 vs. Will Hit: Until the end of the target's next turn, it takes 2d6 psychic damage whenever it enters a square closer to the umber hulk."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 278","Dungeon Magazine 197","Dungeon Magazine 204."] },
  { id:"mv-yuan-ti-malison-chanter",name:"Yuan-ti Malison Chanter",source:"mv",level:15,role:"Artillery",xp:1200,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:118,ac:29,fort:25,ref:27,will:28,initiative:13,perception:13,speed:"7",resist:["10 poison"],powers:[{name:"Bloody Scales",action:"Trait",description:"While bloodied, the yuan-ti gains a +2 bonus to speed and a +2 bonus to all defenses"},{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +18 vs. Fortitude Hit: 2d6 + 6 damage, and ongoing 5 poison damage (save ends)."},{name:"Mind Warp",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 20 (one creature); +20 vs. Will Hit: 4d6 + 9 psychic damage, and the target takes a -2 penalty to attack rolls until the end of the yuan-ti's next turn."},{name:"Poisoned Domination",action:"Standard",keywords:["charm"],recharge:"Recharge when first bloodied",description:"Attack: Ranged 20 (one creature taking ongoing poison damage); +20 vs. Will Hit: The target is dominated until the end of the yuan-ti's next turn."},{name:"Deflect Attack",action:"Triggered",recharge:"Recharge 3-6",description:"Trigger: A melee or a ranged attack hits the yuan-ti. Effect (Immediate Interrupt): The triggering attack instead hits one of the yuan-ti's allies adjacent to it. Skills Bluff +19, Insight +18, Stealth +18"}],alignment:"Unaligned",languages:["Common","Draconic Monster Vault","page(s) 291."] },
  { id:"mv-abyssal-ghoul-devourer",name:"Abyssal Ghoul Devourer",source:"mv",level:16,role:"Lurker",xp:1400,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["undead"],hp:118,ac:30,fort:29,ref:28,will:26,initiative:17,perception:13,speed:"8, climb 4",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Sepulchral Stench",action:"Aura",description:"Aura 3 Enemies take a -2 penalty to all defenses while in the aura"},{name:"Unhindered",action:"Trait",description:"When the ghoul moves on its turn, it pulls with it any creature grabbed by it"},{name:"The",action:"Trait",description:"creature remains grabbed, and this movement does not provoke an opportunity attack from the grabbed creature"},{name:"Grasping Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 2d8 + 3 damage. Effect: The ghoul grabs the target (escape DC 22) if it has fewer than two creatures grabbed. The ghoul then shifts up to half its speed. Until the grab ends, any melee or ranged attack that hits the ghoul deals half damage to the ghoul and half its damage to the target."},{name:"Devour",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the ghoul); +21 vs. AC Hit: 3d10 + 5 damage, and the target is no longer grabbed by the ghoul. In addition, the target takes ongoing 10 damage (save ends). Miss: Half damage, and the target is no longer grabbed by the ghoul. In addition, the target takes ongoing 5 damage (save ends). Skills Stealth +18"}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 129."] },
  { id:"mv-lich-remnant",name:"Lich Remnant",source:"mv",level:16,role:"Artillery",roleModifier:"Minion",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:1,ac:30,fort:25,ref:29,will:28,initiative:10,perception:11,speed:"6",senses:["Darkvision"],resist:["20 necrotic,","20 poison"],immune:["disease"],powers:[{name:"Shadow Touch",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +19 vs. Fortitude Hit: 8 necrotic damage."},{name:"Shadow Ray",action:"Standard",keywords:["necrotic"],description:"Attack: Ranged 20 (one creature); +21 vs. Fortitude Hit: 12 necrotic damage."},{name:"Orb of Obliteration",action:"Standard",keywords:["fire","necrotic"],description:"Attack: Area burst 1 within 20 (enemies in the burst); +21 vs. Reflex Hit: 10 fire and necrotic damage. Miss: Half damage. Obliteration Empowerment ✦ At-Will Effect: Ranged 5 (one lich remnant). The next time the target uses orb of obliteration before the end of its next turn, the size of the power's burst increases by 1, and the power deals 5 extra damage. Obliteration empowerment stacks with other uses of obliteration empowerment."}],alignment:"Unaligned",languages:["Abyssal","Common Monster Vault","page(s) 184."] },
  { id:"mv-rakshasa-mage",name:"Rakshasa Mage",source:"mv",level:16,role:"Controller",xp:1400,size:"Medium",origin:"Natural",type:"Humanoid",hp:153,ac:30,fort:26,ref:29,will:28,initiative:10,perception:11,speed:"6",senses:["Low-light vision"],powers:[{name:"Claw",action:"Standard",keywords:["teleportation"],description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 3d6 + 10 damage, and the rakshasa teleports the target up to 3 squares. Miss: The rakshasa can teleport the target 1 square."},{name:"Misleading Visions",action:"Standard",keywords:["illusion","psychic"],description:"Attack: Area burst 1 within 5 (enemies in the burst); +19 vs. Will Hit: 2d10 + 11 psychic damage, and the rakshasa slides the target up to 4 squares. Miss: The rakshasa can slide the target 1 square."},{name:"Visions of Terror",action:"Standard",keywords:["fear","illusion","psychic"],recharge:"Recharge 4-6",description:"Attack: Area burst 1 within 5 (enemies in the burst); +19 vs. Will Hit: 3d10 + 13 psychic damage, and the target is immobilized (save ends). Miss: Half damage, and the target is slowed until the end of the rakshasa's next turn."},{name:"Deceptive Veil",action:"Minor",keywords:["illusion"],description:"Effect: The rakshasa disguises itself to appear as a Medium humanoid until it uses deceptive veil again or until it drops to 0 hit points. Other creatures can make a DC 36 Insight check to discern that the form is an illusion. Persistent Image (illusion) ✦ At-Will Effect: The rakshasa creates an illusion of a Medium or smaller object or creature in an unoccupied square within 10 squares of it. The illusion can be animate, but it does not produce noise. The illusion lasts until the end of the rakshasa's next turn. A creature that succeeds on a DC 22 Insight check can see through the illusion. Sustain Minor: The illusion persists until the end of the rakshasa's next turn, and the rakshasa can move the illusion up to 6 squares."}],alignment:"Unaligned",languages:["Common Monster Vault","page(s) 245","Dungeon Magazine 196","Dungeon Magazine 200","Dungeon Magazine 201."] },
  { id:"mv-deep-hulk",name:"Deep Hulk",source:"mv",level:17,role:"Brute",roleModifier:"Elite",xp:3200,size:"Large",origin:"Natural",type:"Magical beast",hp:404,ac:29,fort:30,ref:28,will:27,initiative:12,perception:16,speed:"5, burrow 2 (tunneling)",senses:["Darkvision"],powers:[{name:"Claw",action:"Standard",description:"Requirement: The deep hulk must not have a creature grabbed Attack: Melee 2 (one creature); +22 vs. AC Hit: 4d8 + 12 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The deep hulk uses claw twice. If both attacks hit the same target, the deep hulk grabs the target (escape DC 23)."},{name:"Rending Claws",action:"Standard",description:"Effect: Melee 2 (one creature grabbed by the deep hulk). The target takes 60 damage."},{name:"Maddening Gaze",action:"Standard",keywords:["charm"],description:"Attack: Close blast 5 (enemies in the blast); +20 vs. Will Hit: During its next turn, the target takes a standard action to make a basic attack against its nearest ally. If no ally is within range, the target instead takes a standard action to charge its nearest ally it is able to charge."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 279."] },
  { id:"mv-duergar-infernal-consort",name:"Duergar Infernal Consort",source:"mv",level:17,role:"Controller",xp:1600,size:"Medium",origin:"Natural",type:"Humanoid",hp:164,ac:31,fort:30,ref:28,will:30,initiative:8,perception:9,speed:"5",senses:["Darkvision"],resist:["10 fire,","10 poison"],powers:[{name:"Warhammer",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +22 vs. AC Hit: 3d10 + 9 damage, and the duerger infernal consort pushes the target up to 3 squares. The target is slowed until the end of the consort's next turn."},{name:"Devil Possession",action:"Standard",keywords:["charm","fire"],recharge:"Recharge 4-6",description:"Attack: Ranged 3 (one creature); +20 vs. Will Hit: The target is dominated until the end of the consort's next turn. While the target is dominated, any ally of the target that ends its turn adjacent to the target takes 10 fire damage. Effect: At the start of the target's next turn, the consort slides the target up to 3 squares as a free action."},{name:"Infernal Summons",action:"Standard",keywords:["fire","zone"],description:"Attack: Area burst 1 within 5 (creatures in the burst); +20 vs. Reflex Hit: 4d6 + 6 fire damage. Effect: The burst creates a zone of difficult terrain that lasts until the start of the consort's next turn. Any creature that enters the zone or ends its turn there takes 10 fire damage."},{name:"Infernal Quills",action:"Minor",keywords:["poison"],recharge:"Encounter",description:"Attack: Ranged 3 (one creature); +22 vs. AC Hit: 2d8 + 6 damage, and the target takes a -2 penalty to attack rolls and ongoing 10 poison damage (save ends both). Skills Dungeoneering +14, Religion +17"}],alignment:"Unaligned",languages:["Common","Deep Speech","Dwarven Equipment : leather armor","warhammer . Monster Vault","page(s) 97."] },
  { id:"mv-venom-maw-hydra",name:"Venom-Maw Hydra",source:"mv",level:17,role:"Brute",roleModifier:"Solo",xp:8000,size:"Huge",origin:"Natural",type:"Beast",keywords:["reptile","water"],hp:672,ac:31,fort:31,ref:29,will:28,initiative:13,perception:17,speed:"7, swim 10 All-around vision",senses:["Darkvision"],resist:["10 poison"],powers:[{name:"All-Around Vision",action:"Trait",description:"Enemies can't gain combat advantage by flanking the hydra"},{name:"Many Headed",action:"Trait",description:"While stunned or dominated, the hydra can take free actions"},{name:"Regenerating Heads",action:"Trait",description:"The hydra starts an encounter with four heads"},{name:"When",action:"Trait",description:"the hydra's hit points first go below 504, 336, and 168, one of its heads is destroyed"},{name:"Whenever",action:"Trait",description:"a head is destroyed, the hydra grows two heads at the start of its next turn unless it takes fire or acid damage before then"},{name:"Threatening Reach",action:"Trait",description:"The hydra can make opportunity attacks against enemies within 3 squares of it"},{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 3 (one creature); +22 vs. AC Hit: 3d12 damage, and ongoing 10 poison damage, or ongoing 20 poison damage if the hydra is bloodied (save ends)."},{name:"Venomous Spit",action:"Standard",keywords:["poison"],description:"Attack: Ranged 10 (one creature); +20 vs. ReflexThis attack does not provoke opportunity attacks Hit: 2d12 + 5 poison damage, and the target falls prone. Hydra Fury ✦ At-Will Effect: The hydra attacks a number of times equal to the number of heads it currently has, using either bite or venomous spit for each attack. If it has only two heads, it gains a +5 bonus to damage rolls with the attacks. If it has only one head, it gains a +15 bonus to damage rolls with the attack."},{name:"Snapping Jaws",action:"Triggered",description:"Trigger: An enemy ends its turn within 2 squares of the hydra. Effect (Free Action): The hydra uses bite twice against the triggering enemy. Skills Stealth +18"}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 177","Dungeon Magazine 209."] },
  { id:"mv-death-knight-blackguard",name:"Death Knight Blackguard",source:"mv",level:18,role:"Skirmisher",roleModifier:"Elite",xp:4000,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:338,ac:32,fort:31,ref:29,will:27,initiative:17,perception:10,speed:"6",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["10 radiant"],powers:[{name:"Slayer of the Living",action:"Aura",keywords:["fear"],description:"Aura 3 Whenever an enemy ends its turn in the aura, the death knight slides that enemy up to 3 squares."},{name:"Soulsword",action:"Standard",keywords:["necrotic","weapon"],description:"Attack: Melee 1 (one creature); +23 vs. AC Hit: 3d10 + 9 necrotic damage. Effect: The death knight shifts up to 2 squares."},{name:"Double Strike",action:"Standard",description:"Requirement: The death knight must be wielding a soulsword. Effect: The death knight uses soulsword twice, making each attack against a different enemy."},{name:"Overpowering Attack",action:"Standard",keywords:["necrotic","weapon"],description:"Requirement: The death knight must be wielding a soulsword. Attack: Melee 1 (one or two creatures); +23 vs. AC Hit: 3d10 + 9 necrotic damage, and the death knight slides the target up to 2 squares."},{name:"Abyssal Blast",action:"Standard",keywords:["fire","necrotic"],recharge:"Encounter",description:"Attack: Close burst 5 (enemies in the burst); +21 vs. Reflex Hit: 5d6 + 13 fire and necrotic damage. Miss: Half damage."},{name:"Chilling Glare",action:"Minor",keywords:["fear"],recharge:"Recharge 4-6",description:"Effect: Close burst 5 (one enemy in the burst). The target grants combat advantage until the end of the death knight's next turn."},{name:"Implacable",action:"Triggered",description:"Trigger: The death knight becomes marked, slowed, immobilized, dazed, or stunned by an effect. Effect (Opportunity Action): The death knight makes a saving throw to end the triggering effect, even if the effect would not normally end on a save."}],alignment:"Unaligned",languages:["Common Equipment : soulsword","light shield","plate armor . Monster Vault","page(s) 43."] },
  { id:"mv-devil-bred-duergar",name:"Devil-Bred Duergar",source:"mv",level:18,role:"Soldier",roleModifier:"Minion",xp:500,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:34,fort:32,ref:28,will:30,initiative:13,perception:11,speed:"5",senses:["Darkvision"],powers:[{name:"Warhammer",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +23 vs. AC Hit: 13 damage."},{name:"Punishing Hammer",action:"Triggered",keywords:["fire","weapon"],description:"Trigger: An enemy adjacent to the duergar makes an attack that doesn't include it as a target. Attack (Opportunity Action): Melee 1 (the triggering enemy); +23 vs. AC Hit: 13 fire damage."}],alignment:"Unaligned",languages:["Common","Deep Speech","Dwarven Equipment : chainmail","warhammer . Monster Vault","page(s) 98."] },
  { id:"mv-mind-flayer-unseen",name:"Mind Flayer Unseen",source:"mv",level:18,role:"Lurker",xp:2000,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:126,ac:32,fort:28,ref:31,will:30,initiative:20,perception:18,speed:"7",senses:["Darkvision"],powers:[{name:"Unseen Focus",action:"Trait",keywords:["illusion"],description:"The mind flayer is invisible while it has a creature grabbed"},{name:"Tentacles",action:"Standard",description:"Requirement: The mind flayer must not have a creature grabbed. Attack: Melee 1 (one creature); +21 vs. Reflex. This attack automatically hits a dazed or stunned target. Hit: 1d6 + 6 damage, and the mind flayer grabs the target (escape DC 23) if it does not have a creature grabbed."},{name:"Extract Brain",action:"Standard",keywords:["healing"],description:"Attack: Melee 1 (one creature grabbed by the mind flayer); +21 vs. Fortitude Hit: 6d6 + 20 damage, and the target is dazed until it is no longer grabbed. If the attack reduces the target to 0 hit points or fewer, the target dies and the mind flayer regains 15 hit points."},{name:"Mind-Clouding Blast",action:"Standard",keywords:["illusion","psychic"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +21 vs. Will Hit: 3d8 + 7 psychic damage, and the target is dazed (save ends). Miss: Half damage."},{name:"Mental Cloak",action:"Move",keywords:["illusion","teleportation"],recharge:"Recharge when an",description:"attack hits the mind flayer Effect: The mind flayer teleports up to its speed, and it becomes invisible until the end of its next turn. Skills Arcana +20, Insight +18, Stealth +21"}],alignment:"Unaligned",languages:["Deep Speech","telepathy 20 Monster Vault","page(s) 206","Dungeon Magazine 200","Dungeon Magazine 201."] },
  { id:"mv-treant-grove-guardian",name:"Treant Grove Guardian",source:"mv",level:18,role:"Brute",xp:2000,size:"Huge",origin:"Fey",type:"Magical beast",keywords:["plant"],hp:212,ac:30,fort:31,ref:28,will:31,initiative:11,perception:15,speed:"8 (forest walk)",senses:["Low-light vision"],powers:[{name:"Wooden Body Whenever",action:"Trait",description:"the treant takes fire damage, it also takes ongoing 5 fire damage (save ends)"},{name:"Sweeping Slam",action:"Standard",description:"Attack: Melee 3 (one or two creatures); +23 vs. AC Hit: 3d12 + 8 damage, and the target falls prone."},{name:"Stump Stomp",action:"Standard",recharge:"Encounter",description:"Effect: The treant moves up to its speed and can move through enemies' spaces during the move. Each time the treant enters an enemy's space for the first time during the move, it can use slam against that enemy."}],alignment:"Unaligned",languages:["Elven Monster Vault","page(s) 267."] },
  { id:"mv-concordant-mind-flayer",name:"Concordant Mind Flayer",source:"mv",level:19,role:"Controller",xp:0,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:174,ac:33,fort:29,ref:32,will:33,initiative:12,perception:15,speed:"7",senses:["Darkvision"],powers:[{name:"Tentacles",action:"Standard",description:"Requirement: The mind flayer must not have a creature grabbed Attack: Melee 1 (one creature); +22 vs. Reflex. This attack automatically hits a dazed or stunned target Hit: 3d6 + 8 damage, and the mind flayer grabs the target (escape DC 24) if it does not have a creature grabbed."},{name:"Enthrall Brain",action:"Standard",keywords:["charm"],description:"Attack: Melee 1 (one creature grabbed by the mind flayer); +22 vs. Fortitude Hit: 5d6 + 10 damage, and the target is dazed until it is no longer grabbed. If the attack reduces the target to 0 hit points or fewer, the target instead has 1 hit point, and it is dominated until the mind flayer dies."},{name:"Mind Blast",action:"Standard",keywords:["psychic"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +22 vs. Will Hit: 3d8 + 10 psychic damage, and the target is dazed (save ends). If the mind flayer scores a critical hit against the target, the target is dominated instead of dazed (save ends)."},{name:"Shared Pain",action:"Triggered",keywords:["psychic"],description:"Trigger: An ally within 5 squares of the mind flayer takes damage from an attack. Effect (Immediate Reaction): Close burst 5 (one creature dominated by the mind flayer other than the triggering ally in the burst). The target takes 20 psychic damage, which ignores any of the target's resistances. Skills Arcana +21, Insight +20"}],alignment:"Unaligned",languages:["Deep Speech","telepathy 20 Monster Vault","page(s) 207."] },
  { id:"mv-doppelganger-master-assassin",name:"Doppelganger Master Assassin",source:"mv",level:19,role:"Lurker",xp:2400,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["shapechanger"],hp:142,ac:33,fort:31,ref:32,will:29,initiative:20,perception:12,speed:"6",powers:[{name:"Blend In",action:"Trait",description:"While the doppelganger is adjacent to at least one other creature, it can make a Stealth check to become hidden"},{name:"The",action:"Trait",description:"doppelganger remains hidden even if it does not have cover or concealment"},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +24 vs. AC Hit: 3d4 + 6 damage."},{name:"Assassin's Strike",action:"Standard",keywords:["necrotic","weapon"],recharge:"Recharge when the doppelganger uses vanish",description:"Attack: Melee 1 (one creature); +24 vs. AC Hit: 3d4 + 6 damage plus 4d10 + 16 necrotic damage. Miss: 3d10 + 12 necrotic damage. Vanish (illusion) ✦ At-Will Effect: The doppelganger becomes invisible until the end of its next turn and shifts up to its speed."},{name:"Alter Shape",action:"Minor",keywords:["illusion","polymorph"],description:"Effect: The doppelganger alters its physical form to appear as a Medium humanoid and changes the appearance of its clothing and gear until it uses alter shape again or until it drops to 0 hit points. To assume a specific individual's form, the doppelganger must have seen that individual. Other creatures can make a DC 38 Insight check to discern that the form is a disguise. Skills Bluff +20, Insight +17, Stealth +21"}],alignment:"Unaligned",languages:["Common Equipment : dagger . Monster Vault","page(s) 63."] },
  { id:"mv-purple-worm-tunneler",name:"Purple Worm Tunneler",source:"mv",level:19,role:"Skirmisher",roleModifier:"Solo",xp:12000,size:"Huge",origin:"Natural",type:"Beast",keywords:["blind"],hp:728,ac:33,fort:33,ref:31,will:29,initiative:17,perception:14,speed:"8, burrow 8 (tunneling)",senses:["Blindsight 10"],immune:["blinded, gaze effects"],powers:[{name:"Ponderous",action:"Trait",description:"The purple worm can take immediate actions while stunned, dazed, or dominated"},{name:"Blooded Frenzy",action:"Trait",description:"While bloodied, the purple worm takes an extra minor action during its turn"},{name:"Bite",action:"Standard",description:"Attack: Melee 3 (one creature); +24 vs. AC Hit: 4d8 + 9 damage, and the purple worm shifts up to half its speed."},{name:"Devour Whole",action:"Standard",keywords:["acid"],description:"Attack: Melee 3 (one creature); +22 vs. Fortitude Hit: 3d10 + 8 damage, and the target is swallowed (escape DC 24). While swallowed, the target does not occupy a square and has neither line of sight nor line of effect to anything except the worm and other creatures swallowed by the worm; in addition, nothing has line of sight or line of effect to the target except other creatures swallowed by the worm. If the target attacks the worm using a close or an area attack, that attack targets all other creatures swallowed by the worm. While swallowed, the target takes 30 acid damage at the end of its turn. When the effect ends or the worm drops to 0 hit points, the target appears in an unoccupied square of its choice adjacent to the worm."},{name:"Barrel Through",action:"Move",description:"Effect: The purple worm shifts up to its speed. Each time the purple worm enters a square adjacent to any enemy for the first time during the move, it makes the following attack against that enemy. Attack: Melee 1 (one creature); +22 vs. Reflex Hit: 2d8 + 8 damage, and the purple worm pushes the target up to 2 squares."},{name:"Stinger Impalement",action:"Minor",keywords:["poison"],description:"Attack: Melee 3 (one creature); +24 vs. AC Hit: 2d8 + 8 damage, and the purple worm slides the target up to 4 squares. The target takes ongoing 10 poison damage (save ends)."},{name:"Thrash",action:"Triggered",description:"Trigger: An attack hits the purple worm. Attack (Immediate Reaction): Melee 3 (one or two creatures); +22 vs. Reflex Hit: 2d12 + 11 damage, and the purple worm pushes the target up to 6 squares."}],alignment:"Unaligned",languages:["- Monster Vault","page(s) 241."] },
  { id:"mv-duergar-underlord",name:"Duergar Underlord",source:"mv",level:20,role:"Skirmisher",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:364,ac:34,fort:32,ref:33,will:31,initiative:20,perception:15,speed:"7",senses:["Darkvision"],resist:["10 fire,","10 poison"],powers:[{name:"Infernal Animation",action:"Trait",keywords:["healing"],description:"While the duergar underlord is conscious, whenever it starts its turn and no allies within 20 squares of it have at least 1 hit point, one ally within 20 squares returns to life with 1 hit point and can stand up as a free action"},{name:"The",action:"Trait",description:"ally acts immediately after the underlord's turn"},{name:"The",action:"Trait",description:"ally automatically drops to 0 hit points at the end of the encounter"},{name:"Warhammer",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +25 vs. AC Hit: 3d10 + 12 damage. Effect: Any marking effects on the underlord end, and it shifts up to 3 squares."},{name:"Battlecrazed Frenzy",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +25 vs. AC Hit: 3d10 + 12 damage, and the underlord shifts up to 2 squares and repeats this attack against an enemy it has not yet attacked during this turn."},{name:"Infernal Quills",action:"Minor",keywords:["poison"],recharge:"Encounter",description:"Attack: Ranged 3 (one creature); +25 vs. AC Hit: 3d10 + 5 damage, and the target takes a -2 penalty to attack rolls and ongoing 10 poison damage (save ends both). Underlord's Command ✦ At-Will 1/round Effect: Close burst 10 (one ally in the burst). The target can use a free action to shift up to 3 squares and make a basic attack. Skills Dungeoneering +20"}],alignment:"Unaligned",languages:["Common","Deep Speech","Dwarven Equipment : chainmail","warhammer . Monster Vault","page(s) 99."] },
  { id:"mv-dracolich-doomlord",name:"Dracolich Doomlord",source:"mv",level:22,role:"Controller",roleModifier:"Solo",xp:20750,size:"Huge",origin:"Natural",type:"Magical beast",keywords:["dragon","undead"],hp:840,ac:36,fort:35,ref:34,will:32,initiative:18,perception:21,speed:"8, fly 10 (clumsy)",senses:["Darkvision"],resist:["15 necrotic"],immune:["disease, poison"],vulnerable:["10 radiant"],powers:[{name:"Aura of Doom",action:"Aura",description:"Aura 3 Enemies cannot regain hit points or gain temporary hit points while in the aura"},{name:"Action Recovery Whenever",action:"Trait",description:"the dragon ends its turn, any dazing, stunning, or dominating effect on it ends"},{name:"Instinctive Domination On",action:"Trait",description:"an initiative of 10 + its initiative check, the dragon can use a free action to use mesmerizing glance"},{name:"This",action:"Trait",description:"attack does not provoke opportunity attacks"},{name:"If",action:"Trait",description:"the dragon cannot use a free action to make this attack due to a dominating or stunning effect, then that effect ends instead of the dragon making the attack"},{name:"Bite",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 2 (one creature); +27 vs. AC Hit: 2d8 + 8 damage, and ongoing 10 necrotic damage (save ends)."},{name:"Claws",action:"Standard",description:"Attack: Melee 2 (one or two creatures); +27 vs. AC. If the dracolich targets only one creature, it can make this attack twice against that creature Hit: 3d8 + 16 damage. Effect: The dracolich slides the target up to 2 squares."},{name:"Breath Weapon",action:"Standard",keywords:["necrotic"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +25 vs. Reflex Hit: 5d12 + 14 necrotic damage, and the target is weakened (save ends). Miss: Half damage, and the target is weakened until the end of its next turn. Effect: Each target loses any necrotic resistance (save ends)."},{name:"Mesmerizing Glance",action:"Minor",keywords:["charm"],description:"(1/round) Attack: Ranged 5 (one creature); +25 vs. Will Hit: The the target is dominated (save ends). Effect: The dracolich slides the target up to 2 squares."},{name:"Bloodied Breath",action:"Triggered",recharge:"Encounter",description:"Trigger: The dragon is first bloodied. Effect (Free Action): Breath weapon recharges, and the dragon uses it. Skills Insight +21"}],alignment:"Unaligned",languages:["Common","Draconic Monster Vault","page(s) 79."] },
  { id:"mv-lich-soulreaver",name:"Lich Soulreaver",source:"mv",level:22,role:"Artillery",xp:4150,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:156,ac:36,fort:32,ref:36,will:35,initiative:16,perception:14,speed:"6",senses:["Darkvision"],resist:["20 necrotic"],immune:["disease, poison"],powers:[{name:"Necromantic Aura",action:"Aura",keywords:["necrotic"],description:"Aura 5 Any living creature that ends its turn in the aura takes 10 necrotic damage"},{name:"Whenever",action:"Trait",description:"the lich takes radiant damage, its aura is deactivated until the end of the lich's next turn"},{name:"Soul Phylactery",action:"Trait",description:"When the lich drops to 0 hit points, its body and possessions crumble into dust and it disappears, but it is not destroyed"},{name:"It",action:"Trait",description:"reappears (along with its possessions) in 1d10 days within 1 square of its phylactery, unless the phylactery is destroyed"},{name:"Vampiric Touch",action:"Standard",keywords:["healing","necrotic"],description:"Attack: Melee 1 (one creature); +25 vs. Fortitude Hit: 4d8 + 6 necrotic damage, and the lich regains hit points equal to the damage dealt."},{name:"Dark Bolts",action:"Standard",keywords:["lightning","necrotic"],description:"Attack: Ranged 20 (one or two creatures); +27 vs. Reflex Hit: 3d6 + 10 lightning and necrotic damage, and an ally adjacent to the target shifts up to 2 squares."},{name:"Black Flames",action:"Standard",keywords:["fire","necrotic"],recharge:"Recharge when first bloodied",description:"Attack: Area burst 2 within 10 (enemies in the burst); +27 vs. Reflex Hit: 3d10 + 8 fire and necrotic damage, and the target takes ongoing 15 fire and necrotic damage and grants combat advantage (save ends both). Miss: Half damage, and ongoing 10 fire and necrotic damage (save ends)."},{name:"Shadow Walk",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: The lich teleports up to twice its speed. Skills Arcana +24, History +24, Insight +19"}],alignment:"Unaligned",languages:["Abyssal","Common","Elven Monster Vault","page(s) 185."] }
